// @ts-nocheck
import React, { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Activity, ArrowDown, ArrowUp, BarChart3, Download, Filter } from 'lucide-react';
import { api } from '../../lib/api';
import { notify } from '../../lib/notify';

const WINDOWS = [
  { id: '1h', label: '1h' },
  { id: '24h', label: '24h' },
  { id: '7d', label: '7d' },
];

const SORT_KEYS = {
  executions: { label: 'Ejecuciones', fn: (q) => Number(q.calls ?? 0) },
  callsPerMin: { label: 'Calls/min', fn: (q) => Number(q.callsPerMin ?? 0) },
  avgLatency: { label: 'Avg latency', fn: (q) => Number(q.avgLatencySec ?? 0) },
  totalTime: { label: 'Total time', fn: (q) => Number(q.totalTimeSec ?? 0) },
  rowsExamined: { label: 'Rows examined', fn: (q) => Number(q.rowsExamined ?? 0) },
  blksRead: { label: 'Logical reads', fn: (q) => Number(q.blksRead ?? 0) },
  cpuMs: { label: 'CPU ms', fn: (q) => Number(q.cpuMs ?? 0) },
  writes: { label: 'Writes', fn: (q) => Number(q.writes ?? 0) },
  planChanges: { label: 'Plan changes', fn: (q) => Number(q.planChanges ?? 0) },
  regression: { label: 'Regression', fn: (q) => Number(q.regressionScore ?? 0) },
  query: { label: 'Query', fn: (q) => String(q.normalizedText ?? '') },
};

function fmtSec(v, digits = 4) {
  const n = Number(v);
  if (!Number.isFinite(n)) return '—';
  if (n >= 1) return `${n.toFixed(2)} s`;
  if (n >= 0.001) return `${(n * 1000).toFixed(1)} ms`;
  return `${(n * 1e6).toFixed(0)} µs`;
}

function fmtInt(v) {
  const n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return '—';
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 10_000) return `${(n / 1_000).toFixed(1)}K`;
  return String(Math.round(n));
}

function sqlPreview(sql, max = 88) {
  const s = String(sql ?? '').replace(/\s+/g, ' ').trim();
  if (!s) return '—';
  return s.length > max ? `${s.slice(0, max)}…` : s;
}

function shortFp(fp) {
  const s = String(fp ?? '');
  if (!s) return '—';
  const parts = s.split(':');
  const tail = parts[parts.length - 1] ?? s;
  return tail.length > 10 ? `${tail.slice(0, 10)}…` : tail;
}

function exportRowsCsv(rows, connectionName) {
  const cols = [
    ['fingerprint', 'Fingerprint'],
    ['schemaName', 'Schema'],
    ['calls', 'Ejecuciones'],
    ['normalizedText', 'Query'],
    ['callsPerMin', 'Calls/min'],
    ['avgLatencySec', 'Avg latency (s)'],
    ['totalTimeSec', 'Total time (s)'],
    ['rowsExamined', 'Rows examined'],
    ['planChanges', 'Plan changes'],
    ['regressionScore', 'Regression %'],
  ];
  const esc = (v) => {
    const s = String(v ?? '');
    return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
  };
  const lines = [cols.map((c) => esc(c[1])).join(',')];
  for (const r of rows) lines.push(cols.map((c) => esc(r[c[0]])).join(','));
  const blob = new Blob([lines.join('\n')], { type: 'text/csv;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `top-queries-${String(connectionName || 'conn').replace(/[^\w.-]+/g, '_')}-${Date.now()}.csv`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
  notify(`Exportados ${rows.length} registros a CSV`);
}

function exportRowsJson(rows, connectionName) {
  const payload = {
    exportedAt: new Date().toISOString(),
    connection: connectionName,
    queryCount: rows.length,
    queries: rows.map((r) => ({
      fingerprint: r.fingerprint,
      schema: r.schemaName ?? null,
      executions: Number(r.calls ?? 0),
      normalizedText: r.normalizedText,
      callsPerMin: r.callsPerMin,
      avgLatencySec: r.avgLatencySec,
      totalTimeSec: r.totalTimeSec,
      rowsExamined: r.rowsExamined,
      planChanges: r.planChanges,
      regressionScore: r.regressionScore,
    })),
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `top-queries-${String(connectionName || 'conn').replace(/[^\w.-]+/g, '_')}-${Date.now()}.json`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
  notify(`Exportados ${rows.length} registros a JSON`);
}

function cmp(a, b, dir) {
  if (typeof a === 'string' || typeof b === 'string') {
    const r = String(a).localeCompare(String(b), undefined, { sensitivity: 'base' });
    return dir === 'asc' ? r : -r;
  }
  const na = Number(a);
  const nb = Number(b);
  if (na === nb) return 0;
  return dir === 'asc' ? (na < nb ? -1 : 1) : (na > nb ? -1 : 1);
}

function SortTh({ label, sortKey, activeKey, dir, onSort, className = '' }) {
  const active = activeKey === sortKey;
  return (
    <th
      className={`text-left px-2 py-1.5 font-semibold select-none cursor-pointer hover:bg-nv-hover ${className}`}
      onClick={() => onSort(sortKey)}
    >
      <span className="inline-flex items-center gap-0.5">
        {label}
        {active && (dir === 'asc' ? <ArrowUp size={10} /> : <ArrowDown size={10} />)}
      </span>
    </th>
  );
}

function RegressionBadge({ score }) {
  const n = Number(score);
  if (!Number.isFinite(n) || n === 0) {
    return <span className="text-nv-textMuted text-2xs">—</span>;
  }
  const hot = n >= 50;
  const warm = n >= 15;
  return (
    <span
      className={`inline-flex items-center px-1.5 py-0.5 rounded text-2xs font-semibold tabular-nums ${
        hot ? 'bg-red-900/40 text-red-300' : warm ? 'bg-amber-900/40 text-amber-300' : 'bg-slate-800/60 text-slate-300'
      }`}
    >
      {n > 0 ? '+' : ''}{n.toFixed(1)}%
    </span>
  );
}

export function TopQueriesDashboard({ connectionId, connectionName, onSelectQuery }) {
  const [window, setWindow] = useState('24h');
  const [schema, setSchema] = useState('');
  const [sort, setSort] = useState({ key: 'totalTime', dir: 'desc' });

  const { data, isFetching, refetch, error, isLoading } = useQuery({
    queryKey: ['query-store-dashboard', connectionId, window, schema],
    queryFn: () => api.queryStoreDashboard(connectionId, { window, schema, limit: 100 }),
    staleTime: 90_000,
    refetchInterval: window === '1h' ? 120_000 : 180_000,
    refetchIntervalInBackground: false,
    placeholderData: (prev) => prev,
  });

  const { data: originSummary } = useQuery({
    queryKey: ['query-store-origin-summary', connectionId],
    queryFn: () => api.queryStoreOriginSummary(connectionId, 8),
    staleTime: 120_000,
  });

  const rows = data?.queries ?? [];
  const schemas = data?.schemas ?? [];

  const sorted = useMemo(() => {
    const keyDef = SORT_KEYS[sort.key] ?? SORT_KEYS.totalTime;
    return [...rows].sort((a, b) => cmp(keyDef.fn(a), keyDef.fn(b), sort.dir));
  }, [rows, sort]);

  const toggleSort = (key) => {
    setSort((prev) => (prev.key === key ? { key, dir: prev.dir === 'asc' ? 'desc' : 'asc' } : { key, dir: 'desc' }));
  };

  const maxTotal = useMemo(
    () => Math.max(...sorted.map((q) => Number(q.totalTimeSec ?? 0)), 0.0001),
    [sorted],
  );

  return (
    <div className="flex-1 min-h-0 flex flex-col">
      <div className="shrink-0 px-3 py-2 border-b border-nv-border bg-nv-panel/60 flex items-center gap-2 flex-wrap text-2xs">
        <BarChart3 size={12} className="text-sky-500" />
        <span className="font-semibold text-nv-text">Top Queries Dashboard</span>
        <span className="text-nv-textMuted">— {connectionName}</span>

        <span className="text-nv-textSubtle ml-1 flex items-center gap-1">
          <Filter size={10} />
          Window
        </span>
        <div className="flex gap-0.5 p-0.5 rounded border border-nv-border bg-nv-bg">
          {WINDOWS.map((w) => (
            <button
              key={w.id}
              type="button"
              className={`px-2 py-0.5 rounded ${window === w.id ? 'bg-sky-700 text-white' : 'text-nv-textSubtle hover:bg-nv-hover'}`}
              onClick={() => setWindow(w.id)}
            >
              {w.label}
            </button>
          ))}
        </div>

        <label className="text-nv-textSubtle flex items-center gap-1">
          Schema
          <select
            className="nv-input !py-0.5 !text-2xs !h-6 min-w-[7rem]"
            value={schema}
            onChange={(e) => setSchema(e.target.value)}
          >
            <option value="">All</option>
            {schemas.map((s) => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </label>

        <button type="button" className="nv-btn !py-0.5 !text-2xs ml-auto" onClick={() => refetch()}>
          Refresh
        </button>
        <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={() => exportRowsCsv(sorted, connectionName)} title="Exportar a CSV">
          <Download size={10} /> CSV
        </button>
        <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={() => exportRowsJson(sorted, connectionName)} title="Exportar a JSON">
          <Download size={10} /> JSON
        </button>

        {data?.since && (
          <span className="text-nv-textMuted w-full sm:w-auto">
            Since {String(data.since).replace('T', ' ').slice(0, 16)} · {sorted.length} queries
          </span>
        )}
      </div>

      {error && (
        <div className="px-3 py-2 text-2xs text-red-400 border-b border-red-900/30 bg-red-950/20">
          {String(error?.message ?? error)}
        </div>
      )}

      {(originSummary?.applications?.length > 0 || originSummary?.users?.length > 0) && (
        <div className="shrink-0 px-3 py-2 border-b border-nv-border grid grid-cols-2 lg:grid-cols-4 gap-2">
          {[
            ['Applications', originSummary?.applications],
            ['Users', originSummary?.users],
            ['Hosts', originSummary?.hosts],
            ['Drivers', originSummary?.connectors],
          ].map(([title, items]) => (
            <div key={title} className="border border-nv-border rounded px-2 py-1.5 bg-nv-panel/30 text-2xs">
              <div className="font-semibold text-nv-textSubtle mb-1">{title}</div>
              {(items ?? []).slice(0, 3).map((row) => (
                <div key={row.label} className="flex justify-between gap-1 truncate">
                  <span className="truncate font-mono" title={row.label}>{row.label}</span>
                  <span className="tabular-nums text-nv-textMuted shrink-0">{fmtInt(row.executions)}</span>
                </div>
              ))}
            </div>
          ))}
        </div>
      )}

      <div className={`flex-1 min-h-0 overflow-auto ${isFetching ? 'opacity-70' : ''}`}>
        <table className="w-full text-xs table-fixed">
          <thead className="sticky top-0 bg-nv-gridHeader text-2xs text-nv-textSubtle z-10 border-b border-nv-border">
            <tr>
              <th className="text-left px-2 py-1.5 w-24">Fingerprint</th>
              <th className="text-left px-2 py-1.5 w-20">Schema</th>
              <SortTh label="Ejecuciones" sortKey="executions" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} className="w-24 text-right" />
              <SortTh label="Query" sortKey="query" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} />
              <SortTh label="Calls/min" sortKey="callsPerMin" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} className="w-20 text-right" />
              <SortTh label="Avg latency" sortKey="avgLatency" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} className="w-24 text-right" />
              <SortTh label="Total time" sortKey="totalTime" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} className="w-28" />
              <SortTh label="Rows exam." sortKey="rowsExamined" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} className="w-20 text-right" />
              <SortTh label="Plan Δ" sortKey="planChanges" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} className="w-14 text-center" />
              <SortTh label="Regr %" sortKey="regression" activeKey={sort.key} dir={sort.dir} onSort={toggleSort} className="w-16 text-center" />
              <th className="w-8" />
            </tr>
          </thead>
          <tbody>
            {sorted.map((q) => {
              const total = Number(q.totalTimeSec ?? 0);
              const barPct = Math.min(100, (total / maxTotal) * 100);
              return (
                <tr
                  key={q.id}
                  className="border-b border-nv-borderLight hover:bg-nv-hover cursor-pointer"
                  onClick={() => onSelectQuery?.(q.id)}
                >
                  <td className="px-2 py-1.5 font-mono text-2xs text-sky-400" title={q.fingerprint}>
                    {shortFp(q.fingerprint)}
                  </td>
                  <td className="px-2 py-1.5 text-2xs text-nv-textSubtle truncate">{q.schemaName ?? '—'}</td>
                  <td className="px-2 py-1.5 text-right tabular-nums text-2xs">{fmtInt(q.calls)}</td>
                  <td className="px-2 py-1.5 font-mono text-2xs truncate" title={q.normalizedText}>
                    {sqlPreview(q.normalizedText)}
                  </td>
                  <td className="px-2 py-1.5 text-right tabular-nums text-2xs">{Number(q.callsPerMin ?? 0).toFixed(2)}</td>
                  <td className="px-2 py-1.5 text-right tabular-nums text-2xs">{fmtSec(q.avgLatencySec)}</td>
                  <td className="px-2 py-1.5">
                    <div className="flex items-center gap-1.5">
                      <div className="flex-1 h-1.5 bg-nv-border rounded overflow-hidden min-w-[3rem]">
                        <div className="h-full bg-sky-600/80 rounded" style={{ width: `${barPct}%` }} />
                      </div>
                      <span className="text-2xs tabular-nums shrink-0 w-14 text-right">{fmtSec(total, 2)}</span>
                    </div>
                  </td>
                  <td className="px-2 py-1.5 text-right tabular-nums text-2xs">{fmtInt(q.rowsExamined)}</td>
                  <td className="px-2 py-1.5 text-center tabular-nums text-2xs">
                    {Number(q.planChanges) > 0 ? (
                      <span className="text-amber-300 font-semibold">{q.planChanges}</span>
                    ) : (
                      <span className="text-nv-textMuted">—</span>
                    )}
                  </td>
                  <td className="px-2 py-1.5 text-center">
                    <RegressionBadge score={q.regressionScore} />
                  </td>
                  <td className="px-1 py-1.5">
                    <button
                      type="button"
                      className="nv-btn !p-0.5"
                      title="Abrir en detalle"
                      onClick={(e) => { e.stopPropagation(); onSelectQuery?.(q.id); }}
                    >
                      <Activity size={10} className="text-sky-500" />
                    </button>
                  </td>
                </tr>
              );
            })}
            {sorted.length === 0 && !isFetching && (
              <tr>
                <td colSpan={11} className="px-3 py-8 text-center text-nv-textMuted text-2xs">
                  Sin datos en esta ventana — espera snapshots del collector o reduce el rango.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
