// @ts-nocheck
import dagre from 'dagre';

const NODE_W = 180;
const NODE_H = 72;

function asObj(v) {
  return v && typeof v === 'object' && !Array.isArray(v) ? v : null;
}

function readCost(node) {
  const ci = asObj(node.cost_info);
  if (ci?.query_cost != null) return String(ci.query_cost);
  if (ci?.prefix_cost != null) return String(ci.prefix_cost);
  if (node['Total Cost'] != null) return String(node['Total Cost']);
  if (node.cost != null) return String(node.cost);
  return undefined;
}

function readLabel(node) {
  if (node.message) return String(node.message);
  if (node.select_type) return String(node.select_type);
  if (node.access_type) return String(node.access_type);
  if (node.type) return String(node.type);
  if (node['Node Type']) return String(node['Node Type']);
  if (node.nested_loop || node.grouping_operation || node.ordering_operation) return 'query_block';
  return String(node.operation ?? 'Plan');
}

function isClassicRow(node) {
  return !!node.select_type || !!node.access_type || !!node.type || !!node.table;
}

function readTable(node) {
  const t = node.table_name ?? node['Relation Name'] ?? node.Alias ?? node.relation;
  if (t != null) return String(t);
  if (typeof node.table === 'string') return node.table;
  return undefined;
}

let idSeq = 0;
function nextId(prefix) {
  idSeq += 1;
  return `${prefix}-${idSeq}`;
}

function mysqlChildren(node) {
  const out = [];
  for (const key of ['nested_loop', 'grouping_operation', 'ordering_operation', 'duplicates_removal', 'buffer_result']) {
    const v = node[key];
    if (Array.isArray(v)) out.push(...v.map(asObj).filter(Boolean));
    else if (asObj(v)) out.push(asObj(v));
  }
  if (asObj(node.table)) out.push(asObj(node.table));
  if (asObj(node.table_subquery)) out.push(asObj(node.table_subquery));
  if (asObj(node.materialized_from_subquery)) out.push(asObj(node.materialized_from_subquery));
  return out;
}

function flattenClassic(rows) {
  const roots = [];
  const stack = [];
  for (const row of rows) {
    const id = Number(row.id ?? 1);
    const node = {
      id: nextId('classic'),
      label: readLabel(row),
      table: readTable(row),
      cost: row.cost != null ? String(row.cost) : undefined,
      rows: row.rows != null ? String(row.rows) : undefined,
      extra: row.key ?? row.Extra ?? row.possible_keys ? String(row.key ?? row.Extra ?? row.possible_keys) : undefined,
      filter: row.attached_condition ?? row.ref ? String(row.attached_condition ?? row.ref) : undefined,
      indexUsed: !!row.key && String(row.key).length > 0,
      children: [],
    };
    while (stack.length > 0 && stack[stack.length - 1].id >= id) stack.pop();
    if (stack.length === 0) roots.push(node);
    else stack[stack.length - 1].node.children.push(node);
    stack.push({ node, id });
  }
  return roots;
}

function unwrapPlan(raw) {
  if (raw == null) return raw;
  if (typeof raw === 'string') {
    try { return unwrapPlan(JSON.parse(raw)); } catch { return raw; }
  }
  if (Array.isArray(raw)) {
    if (raw.length === 1) return unwrapPlan(raw[0]);
    const objs = raw.map(asObj).filter(Boolean);
    if (objs.length > 0 && objs.every(isClassicRow)) return raw;
    return raw;
  }
  const obj = asObj(raw);
  if (!obj) return raw;
  if (obj.EXPLAIN != null) return unwrapPlan(obj.EXPLAIN);
  if (obj['QUERY PLAN'] != null) return unwrapPlan(obj['QUERY PLAN']);
  if (obj.Plan != null) return unwrapPlan(obj.Plan);
  if (obj.query_block != null) return unwrapPlan(obj.query_block);
  return raw;
}

function collapseSingle(nodes) {
  const mapped = nodes.map((n) => ({ ...n, children: collapseSingle(n.children) }));
  if (mapped.length === 1) {
    const n = mapped[0];
    if ((n.label === 'query_block' || n.label === 'Plan') && n.children.length === 1) {
      return collapseSingle(n.children);
    }
  }
  return mapped;
}

function buildTree(raw, depth = 0) {
  if (raw == null) return [];
  if (Array.isArray(raw)) {
    const objs = raw.map(asObj).filter(Boolean);
    if (objs.length > 0 && objs.every(isClassicRow)) return flattenClassic(objs);
    return raw.flatMap((x) => buildTree(x, depth));
  }
  if (typeof raw === 'string') {
    try { return buildTree(JSON.parse(raw), depth); } catch {
      return [{ id: nextId('txt'), label: raw, children: [] }];
    }
  }
  const node = asObj(raw);
  if (!node) return [];

  const kids = [...mysqlChildren(node)];
  if (Array.isArray(node.Plans)) kids.push(...node.Plans.map(asObj).filter(Boolean));
  if (asObj(node.child)) kids.push(asObj(node.child));

  const childTrees = kids.flatMap((k) => buildTree(k, depth + 1));
  return [{
    id: nextId('n'),
    label: readLabel(node),
    table: readTable(node),
    cost: readCost(node),
    rows: node.rows_examined_per_scan ?? node['Plan Rows'] ?? node.actual_rows != null ? String(node.rows_examined_per_scan ?? node['Plan Rows'] ?? node.actual_rows) : undefined,
    time: node['Actual Total Time'] != null ? String(node['Actual Total Time']) : undefined,
    extra: node.key ?? node['Index Name'] ?? node.possible_keys ?? node.using_index != null ? String(node.key ?? node['Index Name'] ?? node.possible_keys ?? node.using_index) : undefined,
    filter: node.attached_condition ?? node.Filter ?? node.filter != null ? String(node.attached_condition ?? node.Filter ?? node.filter) : undefined,
    loops: node['Actual Loops'] ?? node.actual_loops != null ? String(node['Actual Loops'] ?? node.actual_loops) : undefined,
    indexUsed: !!(node.key ?? node['Index Name'] ?? node.using_index) && String(node.key ?? node['Index Name'] ?? node.using_index).length > 0,
    children: childTrees,
  }];
}

function flattenRows(nodes, depth = 0, out = []) {
  for (const n of nodes) {
    const op = n.label.toLowerCase();
    const risk = op.includes('all') || op.includes('seq scan') ? 'high' : !n.indexUsed && n.table ? 'medium' : 'low';
    out.push({
      id: n.id,
      depth,
      operation: n.label,
      table: n.table,
      cost: n.cost,
      rows: n.rows,
      time: n.time,
      extra: n.extra,
      filter: n.filter,
      loops: n.loops,
      indexUsed: n.indexUsed,
      risk,
    });
    flattenRows(n.children, depth + 1, out);
  }
  return out;
}

function layoutNodes(nodes, edges) {
  const g = new dagre.graphlib.Graph();
  g.setDefaultEdgeLabel(() => ({}));
  g.setGraph({ rankdir: 'LR', nodesep: 50, ranksep: 100 });
  nodes.forEach((n) => g.setNode(n.id, { width: NODE_W, height: NODE_H }));
  edges.forEach((e) => g.setEdge(e.source, e.target));
  dagre.layout(g);
  return nodes.map((n) => {
    const pos = g.node(n.id);
    return { ...n, position: { x: pos.x - NODE_W / 2, y: pos.y - NODE_H / 2 } };
  });
}

export function parseExplainPlan(plan) {
  idSeq = 0;
  const tree = collapseSingle(buildTree(unwrapPlan(plan)));
  const rfNodes = [];
  const rfEdges = [];
  const walk = (nodes) => {
    for (const n of nodes) {
      rfNodes.push({
        id: n.id,
        type: 'planNode',
        data: { label: n.label, table: n.table, cost: n.cost, rows: n.rows, time: n.time, extra: n.extra },
        position: { x: 0, y: 0 },
      });
      for (const c of n.children) {
        rfEdges.push({
          id: `${n.id}->${c.id}`,
          source: n.id,
          target: c.id,
          type: 'smoothstep',
          animated: false,
          markerEnd: { type: 'arrowclosed', color: '#64748b', width: 16, height: 16 },
          style: { stroke: '#64748b', strokeWidth: 2 },
        });
      }
      walk(n.children);
    }
  };
  walk(tree);
  const rows = flattenRows(tree);
  const nodes = layoutNodes(rfNodes, rfEdges).map((n) => ({
    ...n,
    data: { ...n.data, risk: rows.find((r) => r.id === n.id)?.risk },
  }));
  return { nodes, edges: rfEdges, rows, tree };
}

export function explainInsights(rows) {
  const tips = [];
  const hasScan = rows.map((r) => r.operation.toLowerCase()).some((o) => o.includes('all') || o.includes('seq scan') || o.includes('full table'));
  const hasIndex = rows.some((r) => r.extra && /index|key/i.test(r.extra));
  const maxCost = Math.max(...rows.map((r) => parseFloat(String(r.cost ?? '0'))).filter((x) => !Number.isNaN(x)), 0);
  if (hasScan) tips.push({ level: 'danger', title: 'Full table scan detected', detail: 'Consider adding an index or refining WHERE/JOIN predicates.' });
  if (!hasIndex && rows.some((r) => r.table)) tips.push({ level: 'warning', title: 'No index usage detected', detail: 'The plan may read more rows than necessary.' });
  if (maxCost > 1000) tips.push({ level: 'warning', title: 'High estimated cost', detail: `Maximum node cost is ${maxCost.toFixed(2)}.` });
  const slow = rows.filter((r) => r.time && parseFloat(r.time) > 50);
  if (slow.length) tips.push({ level: 'warning', title: 'Slow plan nodes', detail: `${slow.length} node(s) exceed 50ms actual time.` });
  if (!tips.length) tips.push({ level: 'info', title: 'Plan looks healthy', detail: 'No obvious full scans or high-cost hotspots were detected.' });
  return tips;
}

export function normalizePlanInput(planJson) {
  if (planJson == null) return null;
  if (typeof planJson === 'string') {
    try { return JSON.parse(planJson); } catch { return planJson; }
  }
  return planJson;
}
