function sqlPreview(sql, max = 72) {
  const s = String(sql ?? '').replace(/\s+/g, ' ').trim();
  if (!s) return '—';
  return s.length > max ? `${s.slice(0, max)}…` : s;
}

function deriveHintFromPlan(plan, engine) {
  if (!plan) return '';
  const hash = String(plan.planHash ?? '').slice(0, 12);
  const meta = `/* qs-plan:${hash} */`;
  try {
    const raw = typeof plan.planJson === 'string' ? JSON.parse(plan.planJson) : plan.planJson;
    const hints = [];
    const walk = (node) => {
      if (!node || typeof node !== 'object') return;
      if (Array.isArray(node)) {
        node.forEach(walk);
        return;
      }
      const table = node.table_name ?? node['Table Name'] ?? node.relation_name;
      const index = node.key ?? node.index_name ?? node['Key'];
      const access = node.access_type ?? node['Node Type'] ?? node.type;
      if (engine === 'mysql' && table && index && String(index) !== 'PRIMARY' && access && /index/i.test(String(access))) {
        hints.push(`/*+ INDEX(\`${table}\` \`${index}\`) */`);
      }
      if (engine === 'postgres' && table && index && /Index Scan/i.test(String(access))) {
        hints.push(`/*+ IndexScan(${table} ${index}) */`);
      }
      Object.values(node).forEach((v) => {
        if (v && typeof v === 'object') walk(v);
      });
    };
    if (engine === 'mysql' && raw?.query_block) walk(raw.query_block);
    else if (Array.isArray(raw)) raw.forEach((p) => walk(p?.Plan ?? p));
    else walk(raw?.Plan ?? raw);
    const unique = [...new Set(hints)];
    if (unique.length) return `${unique.join('\n')}\n${meta}`;
    return meta;
  } catch {
    return meta;
  }
}

function downloadJson(filename, data) {
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

function downloadText(filename, text, mime = 'text/plain;charset=utf-8') {
  const blob = new Blob([String(text ?? '')], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

