function cmpValues(a, b, dir) {
  if (typeof a === 'string' || typeof b === 'string') {
    const r = String(a).localeCompare(String(b), undefined, { sensitivity: 'base' });
    return dir === 'asc' ? r : -r;
  }
  const na = Number(a);
  const nb = Number(b);
  if (na === nb) return 0;
  return dir === 'asc' ? (na < nb ? -1 : 1) : (na > nb ? -1 : 1);
}

function sortByKey(rows, sortKeys, key, dir) {
  const keyDef = sortKeys[key] ?? Object.values(sortKeys)[0];
  return [...rows].sort((a, b) => cmpValues(keyDef.fn(a), keyDef.fn(b), dir));
}

