function regrPct(recent, hist) {
  const r = Number(recent);
  const h = Number(hist);
  if (!Number.isFinite(r) || !Number.isFinite(h) || h <= 0) return 0;
  return ((r - h) / h) * 100;
}

function buildPlanSummaryRows(plans, history, forcedData, planMeta) {
  const summary = planMeta?.summary;
  if (summary?.length) {
    return summary.map((row) => ({
      hash: row.planHash,
      planId: row.planId ?? String(row.planHash ?? '').slice(0, 8),
      execCount: Number(row.execCount ?? 0),
      avgDuration: Number(row.avgSec ?? 0),
      minDuration: Number(row.minSec ?? row.avgSec ?? 0),
      maxDuration: Number(row.maxSec ?? row.avgSec ?? 0),
      firstExec: row.firstSeen ? new Date(row.firstSeen).getTime() : null,
      lastExec: row.lastSeen ? new Date(row.lastSeen).getTime() : null,
      changed: !!row.changed,
      forced: !!row.isForced,
      isCurrent: !!row.isCurrent,
      isRecommended: !!row.isRecommended,
      status: row.isCurrent ? 'current' : row.isRecommended ? 'recommended' : 'superseded',
      planJson: row.planJson,
      raw: row,
    }));
  }
  const forcedHash = forcedData?.planHash ?? null;
  const map = new Map();
  for (const p of plans ?? []) {
    const hash = p.planHash ?? p.id;
    const prev = map.get(hash);
    if (!prev) map.set(hash, { ...p, captures: [p] });
    else prev.captures.push(p);
  }
  return [...map.entries()].map(([hash, group]) => {
    const times = group.captures
      .map((c) => new Date(c.capturedAt ?? 0).getTime())
      .filter((t) => Number.isFinite(t) && t > 0);
    const capturedAts = new Set(group.captures.map((c) => c.capturedAt));
    let matching = (history ?? []).filter((h) => capturedAts.has(h.capturedAt));
    if (!matching.length && (history ?? []).length) {
      matching = history ?? [];
    }
    const avgs = matching.map((h) => Number(h.avgSec ?? 0)).filter((v) => v > 0);
    const execCount = matching.reduce((s, h) => s + Number(h.callsDelta ?? 0), 0) || group.captures.length;
    const isForced = !!(forcedData?.active && forcedHash && forcedHash === hash);
    return {
      hash,
      planId: String(hash).slice(0, 8),
      execCount,
      avgDuration: avgs.length ? avgs.reduce((a, b) => a + b, 0) / avgs.length : 0,
      minDuration: avgs.length ? Math.min(...avgs) : 0,
      maxDuration: avgs.length ? Math.max(...avgs) : 0,
      firstExec: times.length ? Math.min(...times) : null,
      lastExec: times.length ? Math.max(...times) : null,
      changed: group.captures.some((c) => c.changed),
      forced: isForced,
      isCurrent: hash === planMeta?.currentPlanHash,
      isRecommended: hash === planMeta?.recommendedPlanHash,
      status: hash === planMeta?.currentPlanHash ? 'current' : hash === planMeta?.recommendedPlanHash ? 'recommended' : 'superseded',
      planJson: group.captures[0]?.planJson,
      raw: group.captures[0],
    };
  });
}

