function fmtClock(ts) {
  if (ts == null || ts === '') return '—';
  const d = ts instanceof Date ? ts : new Date(ts);
  if (Number.isNaN(d.getTime())) return '—';
  return d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
}

function ExecutionTimelineChart({ series, maxCalls, height = 108 }) {
  const pad = { l: 30, r: 10, t: 8, b: 26 };
  const w = Math.max(240, series.length * 44 + pad.l + pad.r);
  const h = height;
  const innerW = w - pad.l - pad.r;
  const innerH = h - pad.t - pad.b;
  const slotW = innerW / series.length;
  const ticks = [0, Math.ceil(maxCalls / 2), maxCalls].filter((v, i, a) => a.indexOf(v) === i);

  return (
    <svg
      viewBox={`0 0 ${w} ${h}`}
      className="w-full"
      style={{ height, maxHeight: height }}
      preserveAspectRatio="xMidYMid meet"
    >
      {ticks.map((tick) => {
        const y = pad.t + innerH - (tick / maxCalls) * innerH;
        return (
          <g key={tick}>
            <line x1={pad.l} y1={y} x2={w - pad.r} y2={y} stroke="currentColor" strokeOpacity={0.08} />
            <text x={pad.l - 4} y={y + 3} textAnchor="end" fontSize="8" className="fill-current opacity-40">
              {tick}
            </text>
          </g>
        );
      })}
      <line x1={pad.l} y1={h - pad.b} x2={w - pad.r} y2={h - pad.b} stroke="currentColor" strokeOpacity={0.2} />
      {series.map((p, i) => {
        const calls = Number(p.callsDelta ?? 0);
        const barH = Math.max(4, (calls / maxCalls) * innerH);
        const cx = pad.l + slotW * i + slotW / 2;
        const x = cx - Math.min(22, slotW * 0.5) / 2;
        const y = pad.t + innerH - barH;
        const bw = Math.min(22, Math.max(10, slotW * 0.5));
        const tip = `${fmtHour(p.capturedAt)} · ${calls} ejec. · ${fmtSec(p.totalSecDelta, 2)}${Number(p.rowsDelta) > 0 ? ` · ${fmtInt(p.rowsDelta)} filas` : ''}`;
        return (
          <g key={`${p.capturedAt}-${i}`}>
            <rect
              x={x}
              y={y}
              width={bw}
              height={barH}
              rx={2}
              fill="rgb(34, 197, 94)"
              fillOpacity={0.82}
              stroke="rgb(22, 163, 74)"
              strokeWidth={0.5}
            >
              <title>{tip}</title>
            </rect>
            <text x={cx} y={h - pad.b + 12} textAnchor="middle" fontSize="8" className="fill-current opacity-55">
              {fmtClock(p.capturedAt)}
            </text>
            {calls > 0 && barH > 14 && (
              <text x={cx} y={y + 10} textAnchor="middle" fontSize="7" fill="rgb(220, 252, 231)" fontWeight="600">
                {calls}
              </text>
            )}
          </g>
        );
      })}
    </svg>
  );
}

