/** Minimal, dependency-free Markdown renderer for AI analysis output. */
function AiMarkdown({ text, connectionId, database }) {
  const blocks = useMemo(() => splitMarkdown(text), [text]);
  return (
    <div className="text-2xs leading-relaxed text-nv-text space-y-2">
      {blocks.map((b, i) => {
        if (b.type === 'code') {
          const isSql = looksLikeSql(b.content);
          return (
            <div key={i} className="space-y-1.5">
              <pre className="text-[11px] font-mono whitespace-pre-wrap break-all p-2.5 rounded bg-black/30 border border-nv-border/70 overflow-auto max-h-80">
                {b.content}
              </pre>
              <SqlScriptActions
                sql={b.content}
                connectionId={connectionId}
                database={database}
                showTerminal={isSql}
                copyLabel="Copiar código"
              />
            </div>
          );
        }
        if (b.type === 'h') {
          const lvl = b.level >= 3 ? 'text-2xs font-semibold text-violet-300 mt-2' : 'text-sm font-semibold text-nv-text mt-3';
          return <div key={i} className={lvl}>{b.content}</div>;
        }
        if (b.type === 'li') {
          return (
            <div key={i} className="flex gap-1.5 pl-1">
              <span className="text-nv-textSubtle shrink-0">•</span>
              <span dangerouslySetInnerHTML={{ __html: inlineMd(b.content) }} />
            </div>
          );
        }
        if (b.type === 'hr') return <hr key={i} className="border-nv-border/70 my-1" />;
        return <p key={i} dangerouslySetInnerHTML={{ __html: inlineMd(b.content) }} />;
      })}
    </div>
  );
}

function looksLikeSql(code) {
  const s = String(code ?? '').trim();
  if (!s) return false;
  // Strip leading SQL comments (-- and /* */) for keyword detection.
  const stripped = s.replace(/\/\*[\s\S]*?\*\//g, '').replace(/--[^\n]*/g, '').trim();
  return /^\b(SELECT|INSERT|UPDATE|DELETE|CREATE|DROP|ALTER|EXPLAIN|SHOW|WITH|USE|TRUNCATE|REPLACE|MERGE)\b/i.test(stripped);
}

function splitMarkdown(text) {
  const lines = String(text ?? '').replace(/\r\n/g, '\n').split('\n');
  const out = [];
  let i = 0;
  let para = [];
  const flushPara = () => { if (para.length) { out.push({ type: 'p', content: para.join('\n') }); para = []; } };
  while (i < lines.length) {
    const line = lines[i];
    if (line.startsWith('```')) {
      flushPara();
      const buf = [];
      i++;
      while (i < lines.length && !lines[i].startsWith('```')) { buf.push(lines[i]); i++; }
      out.push({ type: 'code', content: buf.join('\n') });
      i++;
      continue;
    }
    const h = /^(#{1,6})\s+(.*)$/.exec(line);
    if (h) {
      flushPara();
      out.push({ type: 'h', level: h[1].length, content: h[2].trim() });
      i++;
      continue;
    }
    if (/^\s*[-*+]\s+/.test(line)) {
      flushPara();
      const m = /^\s*[-*+]\s+(.*)$/.exec(line);
      out.push({ type: 'li', content: m[1] });
      i++;
      continue;
    }
    if (/^---+$/.test(line.trim())) { flushPara(); out.push({ type: 'hr' }); i++; continue; }
    if (line.trim() === '') { flushPara(); i++; continue; }
    para.push(line);
    i++;
  }
  flushPara();
  return out;
}

function escapeHtml(s) {
  return String(s ?? '').replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
}
function inlineMd(s) {
  let out = escapeHtml(s);
  out = out.replace(/`([^`]+)`/g, '<code class="font-mono text-sky-300">$1</code>');
  out = out.replace(/\*\*([^*]+)\*\*/g, '<strong class="text-nv-text font-semibold">$1</strong>');
  out = out.replace(/\*([^*]+)\*/g, '<em>$1</em>');
  return out;
}

