function buildAnalysis(history, plans, regressionCount, multiplier = 2) {
  const sorted = sortHistoryAsc(history);
  const latest = sorted[sorted.length - 1];
  const previous = sorted.slice(0, -1);
  const baseline =
    previous.length > 0
      ? previous.reduce((s, h) => s + Number(h.avgSec ?? 0), 0) / previous.length
      : Number(latest?.avgSec ?? 0);
  const latestAvg = Number(latest?.avgSec ?? 0);
  const ratio = baseline > 0 ? latestAvg / baseline : 1;
  const planChanges = (plans ?? []).filter((p) => p.changed).length;
  let verdict = 'Rendimiento estable respecto al baseline reciente.';
  let severity = 'ok';
  if (Number(regressionCount) > 0 || ratio >= multiplier) {
    severity = 'warn';
    verdict = `Posible regresión: avg actual ${fmtSec(latestAvg)} vs baseline ${fmtSec(baseline)} (${ratio.toFixed(1)}×).`;
  } else if (ratio <= 0.7 && previous.length > 0) {
    severity = 'good';
    verdict = `Mejora detectada: avg actual ${fmtSec(latestAvg)} vs baseline ${fmtSec(baseline)}.`;
  }
  if (planChanges > 0) {
    severity = 'warn';
    verdict += ` ${planChanges} cambio(s) de plan detectado(s).`;
  }
  return { sorted, latest, baseline, latestAvg, ratio, planChanges, verdict, severity };
}

