export function QueryStorePanel({ connectionId, connectionName }) {
  const qc = useQueryClient();
  const [tab, setTab] = useState('dashboard');
  const [selectedQueryId, setSelectedQueryId] = useState(null);
  const [hintDraft, setHintDraft] = useState('');
  const [enabling, setEnabling] = useState(false);
  const [savingForced, setSavingForced] = useState(false);
  const [capturingPlan, setCapturingPlan] = useState(false);
  const [liveSort, setLiveSort] = useState({ key: 'total', dir: 'desc' });
  const [storedSort, setStoredSort] = useState({ key: 'plans', dir: 'desc' });
  const [regressionSort, setRegressionSort] = useState({ key: 'regr', dir: 'desc' });
  const [navListFilter, setNavListFilter] = useState('');
  const navToken = useQueryStoreNavStore((s) => s.loadToken);
  const navHandledRef = useRef(0);

  const pinnedRaw = useQueryStorePinsStore((s) => s.byConnection[connectionId] ?? EMPTY_PINS);
  const togglePin = useQueryStorePinsStore((s) => s.toggle);
  const unpinPin = useQueryStorePinsStore((s) => s.unpin);
  const clearPinned = useQueryStorePinsStore((s) => s.clear);

  const navPending = navToken > 0 && navHandledRef.current !== navToken;

  const { data: status } = useQuery({
    queryKey: ['query-store-status', connectionId],
    queryFn: () => api.queryStoreStatus(connectionId),
    staleTime: 120_000,
    ...CACHE_FIRST_QUERY,
  });

  const qsReady = status?.available !== false;
  const needsStored = tab === 'stored' || tab === 'regressions' || tab === 'pinned' || tab === 'dashboard' || navPending;

  const { data: topData, isFetching, refetch } = useQuery({
    queryKey: ['query-store-top', connectionId],
    queryFn: () => api.queryStoreTop(connectionId, 50),
    enabled: qsReady && tab === 'live',
    staleTime: 90_000,
    ...CACHE_FIRST_QUERY,
  });

  const { data: storedData, isFetching: loadingStored, isLoading: loadingStoredInitial } = useQuery({
    queryKey: ['query-store-stored', connectionId],
    queryFn: () => api.queryStoreQueries(connectionId, 300),
    enabled: needsStored,
    staleTime: 180_000,
    gcTime: 300_000,
    ...CACHE_FIRST_QUERY,
  });

  const { data: regressionsData } = useQuery({
    queryKey: ['query-store-regressions', connectionId],
    queryFn: () => api.queryStoreRegressions(connectionId),
    enabled: tab === 'regressions',
    staleTime: 90_000,
    ...CACHE_FIRST_QUERY,
  });

  const { data: snapshotsData } = useQuery({
    queryKey: ['query-store-snapshots', connectionId],
    queryFn: () => api.queryStoreSnapshots(connectionId, 20),
    enabled: tab === 'settings' || tab === 'dashboard',
    staleTime: 120_000,
    ...CACHE_FIRST_QUERY,
  });

  const settings = status?.settings ?? {};
  const [cfg, setCfg] = useState(null);
  const form = cfg ?? settings;

  const liveQueries = topData?.queries ?? [];
  const storedQueries = storedData?.queries ?? [];

  const cachedSelectedQuery = useMemo(
    () => (selectedQueryId ? storedQueries.find((q) => q.id === selectedQueryId) ?? null : null),
    [storedQueries, selectedQueryId],
  );

  const { data: selectedQueryData, isFetching: loadingSelectedQuery } = useQuery({
    queryKey: ['query-store-query', connectionId, selectedQueryId],
    queryFn: () => api.queryStoreGetQuery(connectionId, selectedQueryId),
    enabled: !!selectedQueryId && !cachedSelectedQuery && qsReady,
    staleTime: 120_000,
    retry: 1,
  });

  const selectedQuery = cachedSelectedQuery ?? selectedQueryData?.query ?? null;

  const { data: historyData, isFetching: loadingHistory } = useQuery({
    queryKey: ['query-store-history', connectionId, selectedQueryId],
    queryFn: () => api.queryStoreQueryHistory(connectionId, selectedQueryId),
    enabled: !!selectedQueryId && !!selectedQuery && tab !== 'settings',
    staleTime: 120_000,
  });

  const { data: plansData, isFetching: loadingPlans } = useQuery({
    queryKey: ['query-store-plans', connectionId, selectedQueryId],
    queryFn: () => api.queryStoreQueryPlans(connectionId, selectedQueryId),
    enabled: !!selectedQueryId && !!selectedQuery && tab !== 'settings',
    staleTime: 120_000,
  });

  const { data: forcedData } = useQuery({
    queryKey: ['query-store-forced', connectionId, selectedQueryId],
    queryFn: () => api.queryStoreForcedPlan(connectionId, selectedQueryId),
    enabled: !!selectedQueryId && !!selectedQuery && tab !== 'settings',
    staleTime: 180_000,
  });

  const regressions = regressionsData?.regressions ?? [];
  const snapshots = snapshotsData?.snapshots ?? [];
  const history = historyData?.history ?? [];
  const plans = plansData?.plans ?? (Array.isArray(plansData) ? plansData : []);
  const planMeta = plansData?.meta ?? null;

  const maxLiveAvg = useMemo(
    () => Math.max(...liveQueries.map(liveAvgSec), 0.0001),
    [liveQueries],
  );
  const maxStoredAvg = useMemo(
    () => Math.max(...storedQueries.map((q) => Number(q.lastAvgSec ?? 0)), 0.0001),
    [storedQueries],
  );
  const pinnedRows = useMemo(
    () => pinnedRaw.map((p) => {
      const fresh = storedQueries.find((q) => q.id === p.id);
      return fresh ? { ...fresh, pinnedAt: p.pinnedAt } : p;
    }),
    [pinnedRaw, storedQueries],
  );
  const maxPinnedAvg = useMemo(
    () => Math.max(...pinnedRows.map((r) => Number(r.lastAvgSec ?? 0)), 0.0001),
    [pinnedRows],
  );

  const sortedLive = useMemo(
    () => sortByKey(liveQueries, LIVE_SORT_KEYS, liveSort.key, liveSort.dir),
    [liveQueries, liveSort],
  );
  const sortedStored = useMemo(
    () => sortByKey(storedQueries, STORED_SORT_KEYS, storedSort.key, storedSort.dir),
    [storedQueries, storedSort],
  );

  const displayedStored = useMemo(() => {
    const q = navListFilter.trim();
    if (!q) return sortedStored;
    const norm = normSqlForMatch(q);
    const tokens = norm.split(/\W+/).filter((x) => x.length > 2);
    return sortedStored.filter((row) => {
      const rt = normSqlForMatch(row.normalizedText);
      if (rt.includes(norm) || norm.includes(rt)) return true;
      return tokens.some((t) => rt.includes(t));
    });
  }, [sortedStored, navListFilter]);
  const regressedQueries = useMemo(
    () => storedQueries.filter((q) => Number(q.regressionCount) > 0 || regrPct(q.lastAvgSec, q.histAvgSec) >= 15),
    [storedQueries],
  );
  const sortedRegressed = useMemo(
    () => sortByKey(regressedQueries, REGRESSION_SORT_KEYS, regressionSort.key, regressionSort.dir),
    [regressedQueries, regressionSort],
  );

  const toggleSort = (setter, key) => {
    setter((prev) => (prev.key === key ? { key, dir: prev.dir === 'asc' ? 'desc' : 'asc' } : { key, dir: 'desc' }));
  };

  useEffect(() => {
    setSelectedQueryId(null);
    setHintDraft('');
    setNavListFilter('');
    navHandledRef.current = 0;
  }, [connectionId]);

  useEffect(() => {
    if (selectedQueryId) return;
    const nav = useQueryStoreNavStore.getState().payload;
    const navPending = nav?.connectionId === connectionId && nav?.sqlText && navToken > 0
      && navHandledRef.current !== navToken;
    if (navPending) return;
    if (navListFilter.trim()) return;
    const pickList = sortedStored;
    if ((tab === 'stored' || tab === 'live') && pickList.length > 0) {
      setSelectedQueryId(pickList[0].id);
      return;
    }
    if (tab === 'pinned' && pinnedRows.length > 0) {
      setSelectedQueryId(pinnedRows[0].id);
      return;
    }
    if (tab === 'regressions' && sortedRegressed.length > 0) {
      setSelectedQueryId(sortedRegressed[0].id);
    }
  }, [tab, sortedStored, navListFilter, sortedRegressed, selectedQueryId, connectionId, navToken, pinnedRows]);

  useEffect(() => {
    const nav = useQueryStoreNavStore.getState().payload;
    if (!nav || nav.connectionId !== connectionId || navToken === 0) return;
    if (navHandledRef.current === navToken) return;

    if (nav.queryId) {
      setTab('stored');
      setSelectedQueryId(nav.queryId);
      navHandledRef.current = navToken;
      return;
    }

    if (!nav.sqlText) return;
    if (loadingStoredInitial) return;

    let cancelled = false;
    (async () => {
      setTab('stored');
      setNavListFilter(nav.sqlText);
      navHandledRef.current = navToken;

      try {
        const resolved = await api.queryStoreResolve(connectionId, { digestText: nav.sqlText });
        if (cancelled) return;
        if (resolved?.query?.id) {
          const verify = findBestStoredMatch([resolved.query], [], nav.sqlText);
          if (verify.score >= 75) {
            setSelectedQueryId(resolved.query.id);
            notify('Query cargada desde Server Logs');
            return;
          }
        }
      } catch {
        /* fall through to local match */
      }

      const { query: match, score } = findBestStoredMatch(storedQueries, liveQueries, nav.sqlText);
      if (cancelled) return;
      if (match?.id && score >= 70) {
        setSelectedQueryId(match.id);
        notify('Query cargada desde proceso / slow log');
        return;
      }
      if (match?.id && score >= 50) {
        setSelectedQueryId(match.id);
        notify('Coincidencia aproximada — revisa que sea la query correcta');
        return;
      }

      setSelectedQueryId(null);
      notify('No se encontró esta query en Query Store — captura Snapshot o espera el próximo intervalo');
    })();

    return () => {
      cancelled = true;
    };
  }, [navToken, connectionId, storedQueries, liveQueries, loadingStoredInitial]);

  const findStoredByText = (text) => matchLiveToStored(storedQueries, liveQueries, text);

  const openLiveQuery = async (liveRow) => {
    let match = null;
    try {
      const resolved = await api.queryStoreResolve(connectionId, {
        schema: liveRow?.SCHEMA_NAME ?? liveRow?.schema_name ?? liveRow?.database ?? '',
        digest: liveRow?.DIGEST ?? liveRow?.digest ?? '',
        digestText: liveRow?.DIGEST_TEXT ?? liveRow?.query ?? '',
      });
      match = resolved?.query ?? null;
    } catch {
      match = null;
    }
    if (!match?.id) {
      match = matchLiveRowToStored(storedQueries, liveRow);
    }
    if (match?.id) {
      setTab('stored');
      selectQueryId(match.id);
      return;
    }
    notify('Esta query aún no tiene historial en Query Store — espera el próximo snapshot o pulsa Snapshot.');
  };

  const invalidateAll = () => {
    qc.invalidateQueries({ queryKey: ['query-store-top', connectionId] });
    qc.invalidateQueries({ queryKey: ['query-store-stored', connectionId] });
    qc.invalidateQueries({ queryKey: ['query-store-regressions', connectionId] });
    qc.invalidateQueries({ queryKey: ['query-store-snapshots', connectionId] });
    qc.invalidateQueries({ queryKey: ['query-store-status', connectionId] });
  };

  const selectQueryId = (id) => {
    if (!id) return;
    setSelectedQueryId(id);
    setHintDraft('');
    qc.invalidateQueries({ queryKey: ['query-store-history', connectionId, id] });
    qc.invalidateQueries({ queryKey: ['query-store-plans', connectionId, id] });
    qc.invalidateQueries({ queryKey: ['query-store-forced', connectionId, id] });
  };

  const selectQuery = (q) => {
    if (q?.id) selectQueryId(q.id);
  };

  const onEnable = async () => {
    if (!(await confirm('Enable Query Store prerequisites on this server? Requires DBA privileges.', 'Enable Query Store'))) return;
    setEnabling(true);
    try {
      const r = await api.queryStoreEnable(connectionId);
      if (r.available || r.ok) notify('Query Store enabled');
      else if (r.applied?.length) notify(`Partial setup: ${r.applied.join('; ')}`);
      else notifyError(new Error((r.errors ?? []).join('\n') || 'Could not enable Query Store'));
      invalidateAll();
    } catch (e) {
      notifyError(e);
    } finally {
      setEnabling(false);
    }
  };

  const onReset = async () => {
    if (!(await confirm('Reset query statistics on the server?', 'Reset Query Store'))) return;
    try {
      await api.queryStoreReset(connectionId);
      notify('Server stats reset');
      invalidateAll();
    } catch (e) {
      notifyError(e);
    }
  };

  const onSnapshot = async () => {
    try {
      const r = await api.queryStoreSnapshot(connectionId);
      notify(`Snapshot: ${r.stats ?? 0} queries, ${r.plans ?? 0} capturadas, ${r.planVariants ?? r.plans ?? 0} variantes`);
      invalidateAll();
    } catch (e) {
      notifyError(e);
    }
  };

  const onSaveConfig = async () => {
    try {
      await api.queryStoreUpdateConfig(connectionId, form);
      setCfg(null);
      notify('Configuration saved');
      qc.invalidateQueries({ queryKey: ['query-store-status', connectionId] });
    } catch (e) {
      notifyError(e);
    }
  };

  const getForcedContext = () => {
    if (!selectedQuery) return null;
    const hint = (hintDraft || forcedData?.hintSql || '').trim();
    const querySql = buildRunnableQuerySql(
      selectedQuery.normalizedText,
      selectedQuery.schemaName ?? selectedQuery.schema_name,
    );
    const fullSql = composeForcedSql(querySql, hint);
    const database = selectedQuery.schemaName ?? selectedQuery.schema_name ?? undefined;
    return { hint, querySql, fullSql, database };
  };

  const ensureForcedSaved = async () => {
    const ctx = getForcedContext();
    if (!ctx?.hint) {
      notifyError(new Error('Escribe un hint antes de aplicar el forced plan.'));
      return null;
    }
    if (!selectedQueryId) return null;
    const current = (forcedData?.hintSql ?? '').trim();
    if (ctx.hint !== current) {
      setSavingForced(true);
      try {
        await api.queryStoreSetForcedPlan(connectionId, selectedQueryId, ctx.hint);
        qc.invalidateQueries({ queryKey: ['query-store-forced', connectionId, selectedQueryId] });
      } catch (e) {
        notifyError(e);
        return null;
      } finally {
        setSavingForced(false);
      }
    }
    return ctx;
  };

  const onSaveForced = async (hintOverride, planHashOverride = null) => {
    const hint = String(hintOverride ?? hintDraft ?? '').trim();
    if (!selectedQueryId || !hint) return;
    const planHash = planHashOverride ?? planMeta?.currentPlanHash ?? forcedData?.planHash ?? null;
    setSavingForced(true);
    try {
      await api.queryStoreSetForcedPlan(connectionId, selectedQueryId, hint, true, planHash);
      setHintDraft(hint);
      notify('Forced plan guardado');
      qc.invalidateQueries({ queryKey: ['query-store-forced', connectionId, selectedQueryId] });
      qc.invalidateQueries({ queryKey: ['query-store-plans', connectionId, selectedQueryId] });
    } catch (e) {
      notifyError(e);
    } finally {
      setSavingForced(false);
    }
  };

  const onUnforcePlan = async () => {
    if (!selectedQueryId || !forcedData?.hintSql) return;
    setSavingForced(true);
    try {
      await api.queryStoreSetForcedPlan(connectionId, selectedQueryId, forcedData.hintSql, false);
      notify('Forced plan desactivado');
      qc.invalidateQueries({ queryKey: ['query-store-forced', connectionId, selectedQueryId] });
    } catch (e) {
      notifyError(e);
    } finally {
      setSavingForced(false);
    }
  };

  const onSendToTerminal = () => {
    const ctx = getForcedContext();
    if (!ctx) return;
    sendSqlToTerminal({
      connectionId,
      database: ctx.database,
      sql: ctx.fullSql,
    });
  };

  const onCapturePlan = async () => {
    if (!selectedQueryId || capturingPlan) return;
    setCapturingPlan(true);
    try {
      await api.queryStoreQueryPlans(connectionId, selectedQueryId, 50, true);
      qc.invalidateQueries({ queryKey: ['query-store-plans', connectionId, selectedQueryId] });
      notify('Captura de plan solicitada');
    } catch (e) {
      notifyError(e);
    } finally {
      setCapturingPlan(false);
    }
  };

  const onApplyAndRun = async () => {
    const ctx = await ensureForcedSaved();
    if (!ctx) return;
    sendSqlToTerminal({
      connectionId,
      database: ctx.database,
      sql: ctx.fullSql,
      autoRun: true,
      notifyMessage: 'Ejecutando con forced plan en Terminal SQL…',
    });
  };

  const showQueryLoading = !!selectedQueryId && !selectedQuery
    && isInitialLoad(loadingStoredInitial, storedData) && isInitialLoad(loadingSelectedQuery, selectedQueryData);
  const showQueryMissing = !!selectedQueryId && !selectedQuery && !showQueryLoading;

  const detailView = selectedQueryId && selectedQuery ? (
    <QueryDetailView
      query={selectedQuery}
      history={history}
      plans={plans}
      planMeta={planMeta}
      forcedData={forcedData}
      hintDraft={hintDraft}
      setHintDraft={setHintDraft}
      onSaveForced={onSaveForced}
      onUnforcePlan={onUnforcePlan}
      onSendToTerminal={onSendToTerminal}
      onApplyAndRun={onApplyAndRun}
      engine={status?.engine}
      settings={settings}
      loadingHistory={loadingHistory}
      loadingPlans={loadingPlans}
      onCapturePlan={onCapturePlan}
      capturingPlan={capturingPlan}
      connectionName={connectionName}
      connectionId={connectionId}
      savingForced={savingForced}
    />
  ) : showQueryLoading ? (
    <div className="flex-1 flex items-center justify-center text-nv-textMuted text-xs">
      <RefreshCw size={14} className="animate-spin mr-2" /> Cargando query…
    </div>
  ) : navListFilter.trim() && displayedStored.length === 0 ? (
    <div className="flex-1 flex flex-col items-center justify-center text-nv-textMuted text-xs gap-3 p-6 text-center max-w-lg mx-auto">
      <FileCode2 size={28} className="opacity-30" />
      <p className="text-sm text-nv-text">Query no encontrada en las {sortedStored.length} tracked</p>
      <pre className="text-2xs font-mono whitespace-pre-wrap break-all text-left w-full p-3 rounded border border-nv-border bg-nv-panel/50 max-h-32 overflow-auto">
        {navListFilter}
      </pre>
      <p className="text-2xs">Pulsa <strong>Snapshot</strong> para capturarla, o limpia el filtro.</p>
      <button type="button" className="nv-btn !text-2xs" onClick={() => { setNavListFilter(''); setSelectedQueryId(null); }}>
        Limpiar filtro
      </button>
    </div>
  ) : showQueryMissing ? (
    <div className="flex-1 flex flex-col items-center justify-center text-nv-textMuted text-xs gap-2 p-6">
      <AlertTriangle size={24} className="text-amber-400 opacity-80" />
      <p>Query no disponible (puede haber sido purgada).</p>
      <button type="button" className="nv-btn !text-2xs" onClick={() => setSelectedQueryId(null)}>Cerrar</button>
    </div>
  ) : null;

  return (
    <div key={connectionId} className="h-full flex flex-col bg-nv-bg min-h-0">
      {/* Toolbar — SSMS-style */}
      <div className="shrink-0 border-b border-nv-border bg-nv-toolbar">
        <div className="flex items-center gap-2 px-3 py-2 flex-wrap">
          <Database size={14} className="text-sky-500" />
          <span className="font-semibold text-xs">Query Store</span>
          <span className="text-nv-textSubtle text-2xs">— {connectionName}</span>
          <StatusPill available={!!status?.available} />
          <span className="text-2xs text-nv-textMuted px-1.5 py-0.5 rounded bg-nv-panel border border-nv-border">
            {status?.source ?? status?.engine ?? '—'}
          </span>
          <div className="flex gap-1 ml-1 p-0.5 rounded-md border border-nv-border bg-nv-panel/80">
            {TABS.map((t) => {
              const Icon = t.icon;
              return (
                <button
                  key={t.id}
                  type="button"
                  className={`px-2.5 py-1 text-2xs whitespace-nowrap rounded flex items-center gap-1 transition-colors ${
                    tab === t.id
                      ? 'bg-sky-700 text-white shadow-sm'
                      : 'text-nv-textSubtle hover:bg-nv-hover hover:text-nv-text'
                  }`}
                  onClick={() => setTab(t.id)}
                >
                  <Icon size={11} />
                  {t.label}
                </button>
              );
            })}
          </div>
          <div className="ml-auto flex items-center gap-1">
            <button type="button" className="nv-btn !py-0.5" onClick={() => refetch()} title="Refresh">
              <RefreshCw size={11} className={isFetching ? 'animate-spin' : ''} />
            </button>
            <button type="button" className="nv-btn !py-0.5" onClick={onSnapshot} title="Capture snapshot now">
              <Camera size={11} /> Snapshot
            </button>
            <button type="button" className="nv-btn !py-0.5" onClick={onReset} title="Reset server statistics">
              <RotateCcw size={11} /> Reset
            </button>
          </div>
        </div>

        {/* KPI strip */}
        {status?.available && (
          <div className="flex flex-wrap gap-2 px-3 pb-2">
            <KpiCard icon={Clock} label="Snapshots" value={snapshots.length} sub={`every ${settings.intervalMinutes ?? 15} min`} />
            <KpiCard icon={FileCode2} label="Tracked" value={storedQueries.length} sub="query fingerprints" />
            <KpiCard icon={Pin} label="Pinned" value={pinnedRaw.length} sub={pinnedRaw.length ? 'access rápido' : 'none yet'} />
            <KpiCard
              icon={AlertTriangle}
              label="Regressions"
              value={regressions.length}
              sub={regressions.length ? 'review recommended' : 'none detected'}
            />
            <KpiCard icon={TrendingUp} label="Live top" value={liveQueries.length} sub="from performance_schema" />
          </div>
        )}
      </div>

      {!status?.available && (
        <div className="px-4 py-3 text-xs bg-amber-950/20 border-b border-amber-900/30 space-y-2">
          <div className="font-semibold text-amber-400">Query Store is not ready on this connection.</div>
          {(status?.requirements?.items ?? []).map((item) => (
            <div key={item.id} className="flex items-start gap-2">
              {item.ok ? <Check size={12} className="text-emerald-500 mt-0.5" /> : <X size={12} className="text-red-400 mt-0.5" />}
              <span>
                {item.label}
                {item.detail && <span className="block text-nv-textSubtle text-2xs">{item.detail}</span>}
              </span>
            </div>
          ))}
          {status?.canEnable !== false && (
            <button type="button" className="nv-btn-primary !text-xs" onClick={onEnable} disabled={enabling}>
              {enabling ? <RefreshCw size={11} className="animate-spin" /> : <Power size={11} />}
              {enabling ? ' Enabling…' : ' Enable Query Store'}
            </button>
          )}
        </div>
      )}

      {tab === 'dashboard' && (
        <TopQueriesDashboard
          connectionId={connectionId}
          connectionName={connectionName}
          onSelectQuery={(id) => {
            setTab('stored');
            selectQueryId(id);
          }}
        />
      )}

      {/* Top Resource Queries — lista izquierda, detalle derecha */}
      {tab === 'live' && (
        <QuerySplitLayout
          listTitle={`Top resource · ${status?.source ?? status?.engine ?? 'live'}`}
          emptyDetail="Selecciona una query de la lista para ver gráficos y análisis a la derecha."
          hasSelection={!!selectedQueryId}
          detail={detailView}
          listToolbar={(
            <ListToolbar
              sortKeys={LIVE_SORT_KEYS}
              sortKey={liveSort.key}
              sortDir={liveSort.dir}
              onSortKey={(k) => setLiveSort((p) => ({ ...p, key: k }))}
              onToggleDir={() => setLiveSort((p) => ({ ...p, dir: p.dir === 'asc' ? 'desc' : 'asc' }))}
            >
              <span className="text-2xs text-nv-textMuted ml-auto">{sortedLive.length} queries</span>
            </ListToolbar>
          )}
          list={(
            <table className="w-full text-xs table-fixed">
              <thead className="sticky top-0 bg-nv-gridHeader text-2xs text-nv-textSubtle z-10">
                <tr>
                  <th className="text-left px-2 py-1.5 w-8">#</th>
                  <th className="text-left px-2 py-1.5 w-24">DB</th>
                  <th className="text-left px-2 py-1.5">Query</th>
                  <SortableTh label="Calls" sortKey="calls" activeKey={liveSort.key} dir={liveSort.dir} onSort={(k) => toggleSort(setLiveSort, k)} className="w-16" />
                  <SortableTh label="Total" sortKey="total" activeKey={liveSort.key} dir={liveSort.dir} onSort={(k) => toggleSort(setLiveSort, k)} className="w-20" />
                  <SortableTh label="Avg" sortKey="avg" activeKey={liveSort.key} dir={liveSort.dir} onSort={(k) => toggleSort(setLiveSort, k)} className="w-32" />
                  <th className="w-6" />
                </tr>
              </thead>
              <tbody>
                {sortedLive.map((q, i) => {
                  const match = matchLiveRowToStored(storedQueries, q) ?? findStoredByText(q.DIGEST_TEXT ?? q.query);
                  const selected = match && selectedQueryId === match.id;
                  return (
                    <QueryRow
                      key={`${q.DIGEST ?? q.queryid ?? i}`}
                      selected={selected}
                      onSelect={() => openLiveQuery(q)}
                    >
                      <td className="px-2 py-2 text-nv-textMuted tabular-nums">{i + 1}</td>
                      <td className="px-2 py-2 text-nv-textSubtle text-2xs truncate">{q.SCHEMA_NAME ?? q.database ?? '—'}</td>
                      <td className="px-2 py-2 font-mono text-2xs truncate" title={q.DIGEST_TEXT ?? q.query}>
                        {q.DIGEST_TEXT ?? q.query}
                      </td>
                      <td className="px-2 py-2 text-right tabular-nums text-2xs">{liveCalls(q)}</td>
                      <td className="px-2 py-2 text-right tabular-nums text-2xs">{fmtSec(liveTotalSec(q), 2)}</td>
                      <td className="px-2 py-2">
                        <DurationBar value={liveAvgSec(q)} max={maxLiveAvg} />
                      </td>
                    </QueryRow>
                  );
                })}
                {sortedLive.length === 0 && (
                  <tr><td colSpan={7} className="px-3 py-6 text-center text-nv-textMuted text-2xs">No live queries yet.</td></tr>
                )}
              </tbody>
            </table>
          )}
        />
      )}

      {/* Tracked Queries — lista izquierda, detalle derecha */}
      {tab === 'stored' && (
        <QuerySplitLayout
          listTitle="Tracked queries"
          emptyDetail="Selecciona una query de la lista para ver gráficos y análisis a la derecha."
          hasSelection={!!selectedQueryId}
          detail={detailView}
          listToolbar={(
            <ListToolbar
              sortKeys={STORED_SORT_KEYS}
              sortKey={storedSort.key}
              sortDir={storedSort.dir}
              onSortKey={(k) => setStoredSort((p) => ({ ...p, key: k }))}
              onToggleDir={() => setStoredSort((p) => ({ ...p, dir: p.dir === 'asc' ? 'desc' : 'asc' }))}
            >
              <span className="text-2xs text-nv-textMuted ml-auto">
                {navListFilter ? `${displayedStored.length}/${sortedStored.length}` : sortedStored.length} tracked
              </span>
            </ListToolbar>
          )}
          list={(
            <>
              {navListFilter && (
                <div className="px-3 py-1.5 text-2xs border-b border-sky-900/40 bg-sky-950/20 flex items-center gap-2 flex-wrap">
                  <span className="text-sky-300">Filtro desde Server Logs:</span>
                  <code className="font-mono truncate max-w-[70%]">{sqlPreview(navListFilter, 120)}</code>
                  <button type="button" className="nv-btn !py-0.5 !text-2xs ml-auto" onClick={() => setNavListFilter('')}>
                    Limpiar
                  </button>
                </div>
              )}
            <table className="w-full text-xs table-fixed">
              <thead className="sticky top-0 bg-nv-gridHeader text-2xs text-nv-textSubtle z-10">
                <tr>
                  <th className="text-left px-2 py-1.5 w-16">ID</th>
                  <SortableTh label="Plans" sortKey="plans" activeKey={storedSort.key} dir={storedSort.dir} onSort={(k) => toggleSort(setStoredSort, k)} className="w-12 text-center" />
                  <SortableTh label="Schema" sortKey="schema" activeKey={storedSort.key} dir={storedSort.dir} onSort={(k) => toggleSort(setStoredSort, k)} className="w-24" />
                  <SortableTh label="Avg" sortKey="avg" activeKey={storedSort.key} dir={storedSort.dir} onSort={(k) => toggleSort(setStoredSort, k)} className="w-36" />
                  <SortableTh label="!" sortKey="regressions" activeKey={storedSort.key} dir={storedSort.dir} onSort={(k) => toggleSort(setStoredSort, k)} className="w-10 text-center" />
                  <SortableTh label="Query" sortKey="query" activeKey={storedSort.key} dir={storedSort.dir} onSort={(k) => toggleSort(setStoredSort, k)} />
                  <th className="w-6" />
                </tr>
              </thead>
              <tbody>
                {displayedStored.map((q) => {
                  const avg = Number(q.lastAvgSec ?? 0);
                  const selected = selectedQueryId === q.id;
                  return (
                    <QueryRow key={q.id} selected={selected} onSelect={() => selectQueryId(q.id)}>
                      <td className="px-2 py-2 font-mono text-2xs text-sky-400 font-semibold">{shortId(q.id)}</td>
                      <td className="px-1 py-2 text-center tabular-nums text-2xs">{q.planCount ?? 0}</td>
                      <td className="px-2 py-2 text-2xs text-nv-textSubtle truncate">{q.schemaName ?? '—'}</td>
                      <td className="px-2 py-2">
                        <DurationBar value={avg} max={maxStoredAvg} />
                      </td>
                      <td className="px-1 py-2 text-center">
                        {Number(q.regressionCount) > 0 ? (
                          <span className="inline-flex items-center justify-center min-w-[1.25rem] h-5 px-1 rounded-full bg-amber-900/50 text-amber-300 text-2xs font-semibold">
                            {q.regressionCount}
                          </span>
                        ) : (
                          <span className="text-nv-textMuted text-2xs">—</span>
                        )}
                      </td>
                      <td className="px-2 py-2 font-mono text-2xs truncate" title={q.normalizedText}>
                        {q.normalizedText}
                      </td>
                    </QueryRow>
                  );
                })}
                {displayedStored.length === 0 && (
                  <tr><td colSpan={7} className="px-3 py-6 text-center text-nv-textMuted text-2xs">
                    {navListFilter ? 'Sin coincidencias — limpia el filtro o captura Snapshot.' : 'No tracked queries. Capture a snapshot first.'}
                  </td></tr>
                )}
              </tbody>
            </table>
            </>
          )}
        />
      )}

      {/* Pinned Queries — lista izquierda, detalle derecha */}
      {tab === 'pinned' && (
        <QuerySplitLayout
          listTitle="Pinned queries"
          emptyDetail="Fija queries con el botón «Pin query» en el detalle para accesarlas rápido aquí."
          hasSelection={!!selectedQueryId}
          detail={detailView}
          listToolbar={(
            <ListToolbar
              sortKeys={STORED_SORT_KEYS}
              sortKey={storedSort.key}
              sortDir={storedSort.dir}
              onSortKey={(k) => setStoredSort((p) => ({ ...p, key: k }))}
              onToggleDir={() => setStoredSort((p) => ({ ...p, dir: p.dir === 'asc' ? 'desc' : 'asc' }))}
            >
              <button
                type="button"
                className="nv-btn !py-0.5 !text-2xs"
                title="Limpiar todas las queries fijadas de esta conexión"
                disabled={pinnedRows.length === 0}
                onClick={async () => { if (await confirm('¿Quitar todas las queries fijadas de esta conexión?', 'Clear pinned')) clearPinned(connectionId); }}
              >
                Clear
              </button>
              <span className="text-2xs text-nv-textMuted ml-auto">{pinnedRows.length} pinned</span>
            </ListToolbar>
          )}
          list={(
            <table className="w-full text-xs table-fixed">
              <thead className="sticky top-0 bg-nv-gridHeader text-2xs text-nv-textSubtle z-10">
                <tr>
                  <th className="text-left px-2 py-1.5 w-16">ID</th>
                  <th className="text-left px-2 py-1.5 w-12 text-center">Plans</th>
                  <th className="text-left px-2 py-1.5 w-24">Schema</th>
                  <th className="text-left px-2 py-1.5 w-36">Avg</th>
                  <th className="text-left px-2 py-1.5 w-10 text-center">!</th>
                  <th className="text-left px-2 py-1.5">Query</th>
                  <th className="w-10" />
                </tr>
              </thead>
              <tbody>
                {pinnedRows.map((q) => {
                  const avg = Number(q.lastAvgSec ?? 0);
                  const selected = selectedQueryId === q.id;
                  return (
                    <QueryRow key={q.id} selected={selected} onSelect={() => selectQueryId(q.id)}>
                      <td className="px-2 py-2 font-mono text-2xs text-sky-400 font-semibold">{shortId(q.id)}</td>
                      <td className="px-1 py-2 text-center tabular-nums text-2xs">{q.planCount ?? 0}</td>
                      <td className="px-2 py-2 text-2xs text-nv-textSubtle truncate">{q.schemaName ?? '—'}</td>
                      <td className="px-2 py-2">
                        <DurationBar value={avg} max={maxPinnedAvg} />
                      </td>
                      <td className="px-1 py-2 text-center">
                        {Number(q.regressionCount) > 0 ? (
                          <span className="inline-flex items-center justify-center min-w-[1.25rem] h-5 px-1 rounded-full bg-amber-900/50 text-amber-300 text-2xs font-semibold">
                            {q.regressionCount}
                          </span>
                        ) : (
                          <span className="text-nv-textMuted text-2xs">—</span>
                        )}
                      </td>
                      <td className="px-2 py-2 font-mono text-2xs truncate" title={q.normalizedText}>
                        {q.normalizedText ?? '—'}
                      </td>
                      <td className="px-1 py-2 text-center">
                        <button
                          type="button"
                          className="text-nv-textMuted hover:text-amber-300"
                          title="Quitar de Pinned"
                          onClick={(e) => { e.stopPropagation(); unpinPin(connectionId, q.id); if (selectedQueryId === q.id) setSelectedQueryId(null); }}
                        >
                          <Pin size={12} className="fill-current" />
                        </button>
                      </td>
                    </QueryRow>
                  );
                })}
                {pinnedRows.length === 0 && (
                  <tr><td colSpan={7} className="px-3 py-6 text-center text-nv-textMuted text-2xs">
                    Sin queries fijadas. Abre una query en Tracked y pulsa «Pin query».
                  </td></tr>
                )}
              </tbody>
            </table>
          )}
        />
      )}

      {/* Regressed Queries — estilo SSMS TOP REGRESSED */}
      {tab === 'regressions' && (
        <QuerySplitLayout
          listTitle={`Top regressed queries · ${connectionName}`}
          emptyDetail="Selecciona una query regresada para ver plan summary y execution plan."
          hasSelection={!!selectedQueryId}
          detail={detailView}
          listToolbar={(
            <div className="shrink-0 px-3 py-1.5 border-b border-nv-border bg-nv-panel/60 flex items-center gap-3 flex-wrap text-2xs">
              <span className="text-nv-textSubtle">Check regression in:</span>
              <select className="nv-input !py-0.5 !text-2xs !h-6" defaultValue="duration" disabled>
                <option value="duration">Duration</option>
              </select>
              <span className="text-nv-textSubtle">Based on:</span>
              <select className="nv-input !py-0.5 !text-2xs !h-6" defaultValue="avg" disabled>
                <option value="avg">Avg</option>
              </select>
              <label className="text-nv-textSubtle flex items-center gap-1 ml-2">
                Ordenar
                <select
                  className="nv-input !py-0.5 !text-2xs !h-6 min-w-[6rem]"
                  value={regressionSort.key}
                  onChange={(e) => setRegressionSort((p) => ({ ...p, key: e.target.value }))}
                >
                  {Object.entries(REGRESSION_SORT_KEYS).map(([k, v]) => (
                    <option key={k} value={k}>{v.label}</option>
                  ))}
                </select>
              </label>
              <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={() => setRegressionSort((p) => ({ ...p, dir: p.dir === 'asc' ? 'desc' : 'asc' }))}>
                {regressionSort.dir === 'asc' ? <ArrowUp size={11} /> : <ArrowDown size={11} />}
              </button>
              <span className="text-2xs text-nv-textMuted ml-auto">{sortedRegressed.length} queries</span>
            </div>
          )}
          list={(
            <table className="w-full text-xs table-fixed">
              <thead className="sticky top-0 bg-nv-gridHeader text-2xs text-nv-textSubtle z-10">
                <tr>
                  <th className="text-left px-2 py-1.5 w-14">ID</th>
                  <SortableTh label="Query" sortKey="query" activeKey={regressionSort.key} dir={regressionSort.dir} onSort={(k) => toggleSort(setRegressionSort, k)} />
                  <SortableTh label="Regr %" sortKey="regr" activeKey={regressionSort.key} dir={regressionSort.dir} onSort={(k) => toggleSort(setRegressionSort, k)} className="w-14 text-right" />
                  <SortableTh label="Avg recent" sortKey="avgRecent" activeKey={regressionSort.key} dir={regressionSort.dir} onSort={(k) => toggleSort(setRegressionSort, k)} className="w-20 text-right" />
                  <SortableTh label="Avg hist" sortKey="avgHist" activeKey={regressionSort.key} dir={regressionSort.dir} onSort={(k) => toggleSort(setRegressionSort, k)} className="w-20 text-right" />
                  <SortableTh label="Exec recent" sortKey="execRecent" activeKey={regressionSort.key} dir={regressionSort.dir} onSort={(k) => toggleSort(setRegressionSort, k)} className="w-16 text-right" />
                  <SortableTh label="Exec hist" sortKey="execHist" activeKey={regressionSort.key} dir={regressionSort.dir} onSort={(k) => toggleSort(setRegressionSort, k)} className="w-16 text-right" />
                  <SortableTh label="Plans" sortKey="plans" activeKey={regressionSort.key} dir={regressionSort.dir} onSort={(k) => toggleSort(setRegressionSort, k)} className="w-12 text-center" />
                  <th className="w-6" />
                </tr>
              </thead>
              <tbody>
                {sortedRegressed.map((q) => {
                  const selected = selectedQueryId === q.id;
                  const pct = regrPct(q.lastAvgSec, q.histAvgSec);
                  return (
                    <QueryRow key={q.id} selected={selected} onSelect={() => selectQueryId(q.id)}>
                      <td className="px-2 py-2 font-mono text-2xs text-sky-400 font-semibold">{shortId(q.id)}</td>
                      <td className="px-2 py-2 font-mono text-2xs truncate" title={q.normalizedText}>{q.normalizedText}</td>
                      <td className={`px-2 py-2 text-right tabular-nums font-semibold ${pct >= 50 ? 'text-red-400' : pct >= 15 ? 'text-amber-400' : 'text-nv-textSubtle'}`}>
                        {pct > 0 ? `+${pct.toFixed(0)}%` : `${pct.toFixed(0)}%`}
                      </td>
                      <td className="px-2 py-2 text-right tabular-nums">{fmtSec(q.lastAvgSec, 3)}</td>
                      <td className="px-2 py-2 text-right tabular-nums text-nv-textSubtle">{fmtSec(q.histAvgSec, 3)}</td>
                      <td className="px-2 py-2 text-right tabular-nums">{fmtInt(q.execCountRecent)}</td>
                      <td className="px-2 py-2 text-right tabular-nums text-nv-textSubtle">{fmtInt(q.execCountHist)}</td>
                      <td className="px-2 py-2 text-center tabular-nums">{q.planCount ?? 0}</td>
                    </QueryRow>
                  );
                })}
                {sortedRegressed.length === 0 && (
                  <tr>
                    <td colSpan={9} className="px-3 py-6 text-center text-nv-textMuted text-2xs">
                      No regressed queries. Scheduler every {settings.intervalMinutes ?? 15} min.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          )}
        />
      )}

      {/* Configuration */}
      {tab === 'settings' && (
        <div className="flex-1 overflow-auto p-4">
          <div className="max-w-lg space-y-4">
            <div className="flex items-center justify-between gap-2">
              <div className="text-sm font-semibold">Query Store Configuration</div>
              <button
                type="button"
                className="nv-btn text-2xs"
                onClick={() => useSettingsModalStore.getState().openSettings('queryStore')}
              >
                Open in Configuration
              </button>
            </div>
            <p className="text-2xs text-nv-textSubtle">
              Paridad con SQL Server Query Store: modo de captura, re-captura periódica, retención y sensibilidad de regresión.
            </p>
            <div className="space-y-3 p-3 border border-nv-border rounded bg-nv-panel/40">
              <label className="flex items-center gap-2 text-xs">
                <input
                  type="checkbox"
                  checked={form.enabled !== false}
                  onChange={(e) => setCfg({ ...form, enabled: e.target.checked })}
                />
                <span><strong>Operation mode:</strong> automatic snapshot collection (scheduler)</span>
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Query Capture Mode (AUTO / ALL / NONE)</span>
                <select
                  className="nv-select w-full mt-1"
                  value={form.captureMode ?? 'auto'}
                  onChange={(e) => setCfg({ ...form, captureMode: e.target.value })}
                >
                  <option value="auto">AUTO — queries due + top by latency</option>
                  <option value="all">ALL — rotate all tracked queries</option>
                  <option value="none">NONE — stats only, no EXPLAIN</option>
                </select>
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Data collection interval (minutes)</span>
                <input
                  type="number"
                  min={1}
                  max={1440}
                  className="nv-input w-full mt-1"
                  value={form.intervalMinutes ?? 15}
                  onChange={(e) => setCfg({ ...form, intervalMinutes: parseInt(e.target.value, 10) || 15 })}
                />
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Plans captured per snapshot (budget)</span>
                <input
                  type="number"
                  min={1}
                  max={200}
                  className="nv-input w-full mt-1"
                  value={form.plansPerSnapshot ?? 25}
                  onChange={(e) => setCfg({ ...form, plansPerSnapshot: parseInt(e.target.value, 10) || 25 })}
                />
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Re-capture every N snapshots (even if plan unchanged)</span>
                <input
                  type="number"
                  min={1}
                  max={50}
                  className="nv-input w-full mt-1"
                  value={form.planRecaptureEvery ?? 4}
                  onChange={(e) => setCfg({ ...form, planRecaptureEvery: parseInt(e.target.value, 10) || 4 })}
                />
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">SQL samples per query (from performance_schema history)</span>
                <input
                  type="number"
                  min={1}
                  max={20}
                  className="nv-input w-full mt-1"
                  value={form.sampleSqlPerQuery ?? 5}
                  onChange={(e) => setCfg({ ...form, sampleSqlPerQuery: parseInt(e.target.value, 10) || 5 })}
                />
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Retention (days) — purge old snapshots</span>
                <input
                  type="number"
                  min={1}
                  max={365}
                  className="nv-input w-full mt-1"
                  value={form.retentionDays ?? 30}
                  onChange={(e) => setCfg({ ...form, retentionDays: parseInt(e.target.value, 10) || 30 })}
                />
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Legacy top-N hint (AUTO mode tie-breaker)</span>
                <input
                  type="number"
                  min={1}
                  max={50}
                  className="nv-input w-full mt-1"
                  value={form.topNPlans ?? 10}
                  onChange={(e) => setCfg({ ...form, topNPlans: parseInt(e.target.value, 10) || 10 })}
                />
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Regression threshold (× baseline avg of last K snapshots)</span>
                <input
                  type="number"
                  min={1}
                  max={10}
                  step={0.1}
                  className="nv-input w-full mt-1"
                  value={form.regressionMultiplier ?? 2}
                  onChange={(e) => setCfg({ ...form, regressionMultiplier: parseFloat(e.target.value) || 2 })}
                />
              </label>
              <label className="block text-xs">
                <span className="text-nv-textSubtle">Baseline lookback (K snapshots)</span>
                <input
                  type="number"
                  min={1}
                  max={20}
                  className="nv-input w-full mt-1"
                  value={form.regressionLookback ?? 5}
                  onChange={(e) => setCfg({ ...form, regressionLookback: parseInt(e.target.value, 10) || 5 })}
                />
              </label>
              <button type="button" className="nv-btn-primary" onClick={onSaveConfig}>
                Save configuration
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
