// @ts-nocheck
import React, { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Users, Server, AppWindow, Plug, Clock, Activity, Download } from 'lucide-react';
import { api } from '../../lib/api';
import { ExportButtons } from '../../components/ui/ExportButtons';

function fmtInt(v) {
  const n = Number(v);
  if (!Number.isFinite(n) || n <= 0) return '—';
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 10_000) return `${(n / 1_000).toFixed(1)}K`;
  return String(Math.round(n));
}

function fmtTime(ts) {
  if (!ts) return '—';
  const d = new Date(ts);
  if (Number.isNaN(d.getTime())) return String(ts).replace('T', ' ').slice(0, 16);
  return d.toLocaleString(undefined, { month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit' });
}

function OriginBarList({ title, icon: Icon, items, emptyLabel = 'Sin datos aún', filenamePrefix }) {
  const rows = items ?? [];
  const max = Math.max(...rows.map((r) => Number(r.pct ?? r.count ?? 0)), 1);
  return (
    <div className="border border-nv-border rounded bg-nv-panel/30 overflow-hidden">
      <div className="px-3 py-1.5 border-b border-nv-border bg-nv-gridHeader flex items-center gap-1.5 text-2xs font-semibold">
        <Icon size={11} className="text-sky-500" />
        <span className="flex-1">{title}</span>
        {rows.length > 0 && filenamePrefix && (
          <ExportButtons rows={rows} filenamePrefix={filenamePrefix} />
        )}
      </div>
      <div className="p-2 space-y-1.5">
        {rows.length === 0 && (
          <div className="text-2xs text-nv-textMuted py-3 text-center">{emptyLabel}</div>
        )}
        {rows.slice(0, 20).map((row) => {
          const pct = Number(row.pct ?? 0);
          const bar = row.pct != null ? pct : (Number(row.count ?? 0) / max) * 100;
          return (
            <div key={row.label} className="text-2xs">
              <div className="flex justify-between gap-2 mb-0.5">
                <span className="font-mono truncate" title={row.label}>{row.label}</span>
                <span className="tabular-nums text-nv-textMuted shrink-0">{row.pct != null ? `${pct}%` : fmtInt(row.count)}</span>
              </div>
              <div className="h-1.5 bg-nv-border rounded overflow-hidden">
                <div className="h-full bg-sky-600/75 rounded" style={{ width: `${Math.min(100, bar)}%` }} />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function OriginTimeline({ timeline, window }) {
  const buckets = useMemo(() => {
    const map = new Map();
    for (const row of timeline ?? []) {
      const key = String(row.applicationName || row.userName || row.hostName || 'unknown');
      const t = String(row.capturedAt ?? '').slice(0, 16);
      if (!map.has(t)) map.set(t, {});
      const slot = map.get(t);
      slot[key] = (slot[key] ?? 0) + Number(row.calls ?? 0);
    }
    return [...map.entries()].sort((a, b) => a[0].localeCompare(b[0])).slice(-12);
  }, [timeline]);

  if (!buckets.length) {
    return (
      <div className="text-2xs text-nv-textMuted py-4 text-center border border-dashed border-nv-border rounded">
        Timeline vacío — se llena tras snapshots con atribución de origen.
      </div>
    );
  }

  const labels = [...new Set(buckets.flatMap(([, v]) => Object.keys(v)))].slice(0, 5);
  const colors = ['bg-sky-600', 'bg-emerald-600', 'bg-amber-600', 'bg-violet-600', 'bg-rose-600'];

  return (
    <div className="border border-nv-border rounded bg-nv-panel/30 p-3">
      <div className="text-2xs font-semibold text-nv-textSubtle mb-2 flex items-center gap-1">
        <Activity size={11} className="text-sky-500" />
        Timeline · {window}
      </div>
      <div className="space-y-1">
        {buckets.map(([time, counts]) => {
          const total = Object.values(counts).reduce((s, n) => s + n, 0) || 1;
          return (
            <div key={time} className="flex items-center gap-2 text-2xs">
              <span className="w-16 shrink-0 text-nv-textMuted tabular-nums">{time.slice(11, 16) || time}</span>
              <div className="flex-1 h-3 flex rounded overflow-hidden bg-nv-border/40">
                {labels.map((label, i) => {
                  const v = counts[label] ?? 0;
                  if (v <= 0) return null;
                  return (
                    <div
                      key={label}
                      className={`${colors[i % colors.length]} opacity-85`}
                      style={{ width: `${(v / total) * 100}%` }}
                      title={`${label}: ${v}`}
                    />
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
      <div className="flex flex-wrap gap-2 mt-2">
        {labels.map((label, i) => (
          <span key={label} className="inline-flex items-center gap-1 text-2xs text-nv-textMuted">
            <span className={`w-2 h-2 rounded-sm ${colors[i % colors.length]}`} />
            {label}
          </span>
        ))}
      </div>
    </div>
  );
}

export function QueryOriginPanel({ connectionId, queryId, showRegression = false }) {
  const { data, isFetching } = useQuery({
    queryKey: ['query-store-origin', connectionId, queryId],
    queryFn: () => api.queryStoreQueryOrigin(connectionId, queryId),
    enabled: !!queryId,
    staleTime: 90_000,
  });

  const { data: timelineData } = useQuery({
    queryKey: ['query-store-origin-timeline', connectionId, queryId],
    queryFn: () => api.queryStoreOriginTimeline(connectionId, queryId, '1h'),
    enabled: !!queryId,
    staleTime: 90_000,
  });

  const summary = data?.summary ?? {};

  const correlation = useMemo(() => {
    if (!showRegression || !(data?.sources?.length)) return null;
    const top = data.sources[0];
    const total = Math.max(1, Number(summary.totalExecutions ?? 0));
    return {
      application: top.applicationName,
      user: top.userName,
      host: top.hostName,
      contributionPct: Math.round((Number(top.executionCount ?? 0) / total) * 100),
      planChanges: 0,
    };
  }, [showRegression, data, summary.totalExecutions]);

  return (
    <div className={`h-full min-h-0 overflow-y-auto overscroll-contain p-3 space-y-3 ${isFetching ? 'opacity-70' : ''}`}>
      <div className="flex items-center gap-2 shrink-0">
        <span className="text-2xs text-nv-textSubtle flex-1">
          Origen de ejecuciones · query <span className="font-mono text-sky-400">{queryId}</span>
        </span>
        {data?.sources?.length > 0 && (
          <ExportButtons rows={data.sources} filenamePrefix={`origin-sources-${queryId}`} />
        )}
      </div>
      {correlation && (
        <div className="border border-amber-900/40 bg-amber-950/20 rounded px-3 py-2 text-2xs space-y-1">
          <div className="font-semibold text-amber-300">Regression correlation</div>
          <div className="text-nv-textSubtle">
            {correlation.application && <span>App: <strong className="text-nv-text">{correlation.application}</strong> · </span>}
            {correlation.user && <span>User: <strong className="text-nv-text">{correlation.user}</strong> · </span>}
            {correlation.host && <span>Host: <strong className="text-nv-text">{correlation.host}</strong> · </span>}
            <span>Contribution: <strong className="text-amber-300">{correlation.contributionPct}%</strong></span>
            {correlation.planChanges > 0 && <span> · Plan change: <strong className="text-amber-300">Yes</strong></span>}
          </div>
        </div>
      )}

      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 text-2xs">
        <div className="border border-nv-border rounded px-2 py-1.5 bg-nv-panel/40">
          <div className="text-nv-textMuted flex items-center gap-1"><Clock size={10} /> First seen</div>
          <div className="font-medium mt-0.5">{fmtTime(summary.firstSeen)}</div>
        </div>
        <div className="border border-nv-border rounded px-2 py-1.5 bg-nv-panel/40">
          <div className="text-nv-textMuted flex items-center gap-1"><Clock size={10} /> Last seen</div>
          <div className="font-medium mt-0.5">{fmtTime(summary.lastSeen)}</div>
        </div>
        <div className="border border-nv-border rounded px-2 py-1.5 bg-nv-panel/40">
          <div className="text-nv-textMuted">Executions</div>
          <div className="font-semibold text-emerald-400 mt-0.5 tabular-nums">{fmtInt(summary.totalExecutions)}</div>
        </div>
        <div className="border border-nv-border rounded px-2 py-1.5 bg-nv-panel/40">
          <div className="text-nv-textMuted">Total time</div>
          <div className="font-semibold text-sky-400 mt-0.5 tabular-nums">{Number(summary.totalTimeSec ?? 0).toFixed(2)} s</div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
        <OriginBarList title="Users" icon={Users} items={data?.users} filenamePrefix={`origin-users-${queryId}`} />
        <OriginBarList title="Hosts" icon={Server} items={data?.hosts} filenamePrefix={`origin-hosts-${queryId}`} />
        <OriginBarList title="Applications" icon={AppWindow} items={data?.applications} filenamePrefix={`origin-apps-${queryId}`} />
        <OriginBarList title="Client drivers" icon={Plug} items={data?.connectors} filenamePrefix={`origin-drivers-${queryId}`} />
      </div>

      <OriginTimeline timeline={timelineData?.timeline} window="Last hour" />
    </div>
  );
}
