// @ts-nocheck
import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';

export type PinnedQuery = {
  id: string;
  schemaName?: string;
  normalizedText?: string;
  lastAvgSec?: number;
  regressionCount?: number;
  planCount?: number;
  pinnedAt: number;
};

// Stable empty array for selectors — returning a fresh [] from a zustand
// selector breaks useSyncExternalStore (new snapshot every call → render loop).
const EMPTY: PinnedQuery[] = Object.freeze([]);
export const EMPTY_PINS: PinnedQuery[] = EMPTY;

type PinsState = {
  byConnection: Record<string, PinnedQuery[]>;
  toggle: (connId: string, q: PinnedQuery) => void;
  pin: (connId: string, q: PinnedQuery) => void;
  unpin: (connId: string, id: string) => void;
  isPinned: (connId: string, id: string) => boolean;
  list: (connId: string) => PinnedQuery[];
  clear: (connId: string) => void;
};

export const useQueryStorePinsStore = create<PinsState>()(
  persist(
    (set, get) => ({
      byConnection: {},
      toggle: (connId, q) => {
        const cur = get().byConnection[connId] ?? [];
        const exists = cur.some((p) => p.id === q.id);
        set({
          byConnection: {
            ...get().byConnection,
            [connId]: exists ? cur.filter((p) => p.id !== q.id) : [{ ...q, pinnedAt: Date.now() }, ...cur],
          },
        });
      },
      pin: (connId, q) => {
        const cur = get().byConnection[connId] ?? [];
        if (cur.some((p) => p.id === q.id)) return;
        set({ byConnection: { ...get().byConnection, [connId]: [{ ...q, pinnedAt: Date.now() }, ...cur] } });
      },
      unpin: (connId, id) => {
        const cur = get().byConnection[connId] ?? [];
        set({ byConnection: { ...get().byConnection, [connId]: cur.filter((p) => p.id !== id) } });
      },
      isPinned: (connId, id) => (get().byConnection[connId] ?? []).some((p) => p.id === id),
      list: (connId) => get().byConnection[connId] ?? [],
      clear: (connId) => set({ byConnection: { ...get().byConnection, [connId]: [] } }),
    }),
    {
      name: 'nv-query-store-pins',
      storage: createJSONStorage(() => localStorage),
      partialize: (s) => ({ byConnection: s.byConnection }),
    },
  ),
);
