// @ts-nocheck
import React, { useEffect, useMemo, useState } from 'react';
import ReactFlow, { Background, Controls, Handle, MiniMap, Position, useReactFlow } from 'reactflow';
import 'reactflow/dist/style.css';
import { AlertTriangle, Info, Lightbulb } from 'lucide-react';
import { explainInsights, normalizePlanInput, parseExplainPlan } from '../../lib/explain-plan';
import { AiAnalysisButton } from '../ai/AiAnalysisButton';

function FitViewOnLoad({ count }) {
  const { fitView } = useReactFlow();
  useEffect(() => {
    if (count > 0) {
      const t = window.setTimeout(() => fitView({ padding: 0.25, maxZoom: 1.2 }), 50);
      return () => window.clearTimeout(t);
    }
  }, [count, fitView]);
  return null;
}

function PlanNode({ data }) {
  const hasTable = !!data.table;
  const cls = data.risk === 'high' ? 'nv-plan-node-danger' : data.risk === 'medium' ? 'nv-plan-node-warn' : 'nv-plan-node-ok';
  return (
    <div className={`nv-plan-node rounded border shadow-sm text-2xs min-w-[160px] relative ${cls}`}>
      <Handle type="target" position={Position.Left} className="!w-2 !h-2 !bg-slate-400 !border-slate-600" />
      {data.cost && <div className="text-center text-[10px] font-mono text-nv-textSubtle pt-1">{data.cost}</div>}
      <div className="px-2 py-1.5 text-center font-medium">
        {hasTable ? (
          <div className="flex flex-col items-center gap-0.5">
            <span className="nv-plan-table-icon">▦</span>
            <span className="font-mono text-[11px]">{data.table}</span>
            {data.label && data.label !== data.table && <span className="text-[10px] text-nv-textMuted">{data.label}</span>}
          </div>
        ) : (
          <span className="text-[11px]">{data.label}</span>
        )}
      </div>
      {(data.rows || data.time || data.extra) && (
        <div className="px-2 pb-1.5 text-[10px] text-nv-textMuted text-center border-t border-nv-borderLight space-y-0.5">
          {data.rows && <div>rows: {data.rows}</div>}
          {data.time && <div>time: {data.time}ms</div>}
          {data.extra && <div className="truncate max-w-[150px]" title={data.extra}>idx: {data.extra}</div>}
        </div>
      )}
      <Handle type="source" position={Position.Right} className="!w-2 !h-2 !bg-slate-400 !border-slate-600" />
    </div>
  );
}

const nodeTypes = { planNode: PlanNode };

function StatCard({ label, value }) {
  return (
    <div className="border border-nv-border rounded p-2 bg-nv-toolbar">
      <div className="text-2xs text-nv-textMuted">{label}</div>
      <div className="font-semibold mt-0.5">{value}</div>
    </div>
  );
}

function InsightCard({ insight }) {
  const Icon = insight.level === 'danger' || insight.level === 'warning' ? AlertTriangle : Info;
  const cls = insight.level === 'danger' ? 'nv-insight-danger' : insight.level === 'warning' ? 'nv-insight-warn' : 'nv-insight-info';
  return (
    <div className={`nv-insight ${cls}`}>
      <Icon size={14} className="shrink-0 mt-0.5" />
      <div>
        <div className="font-semibold">{insight.title}</div>
        <div className="text-nv-textSubtle mt-0.5">{insight.detail}</div>
      </div>
    </div>
  );
}

export function ExplainPlanViewer({
  plan,
  engine,
  error,
  loading,
  defaultTab = 'grid',
  compact = false,
  sql,
  connectionId,
  database,
}) {
  const [tab, setTab] = useState(defaultTab);
  const normalized = useMemo(() => normalizePlanInput(plan), [plan]);
  const parsed = useMemo(() => (normalized ? parseExplainPlan(normalized) : { nodes: [], edges: [], rows: [] }), [normalized]);
  const insights = useMemo(() => explainInsights(parsed.rows), [parsed.rows]);
  const maxCost = useMemo(() => {
    const costs = parsed.rows.map((r) => parseFloat(String(r.cost ?? '0'))).filter((x) => !Number.isNaN(x));
    return costs.length ? Math.max(...costs) : 0;
  }, [parsed.rows]);

  const minH = compact ? 'min-h-[200px]' : 'min-h-[240px]';

  if (loading) {
    return <div className={`h-full flex items-center justify-center text-xs text-nv-textMuted ${minH}`}>Running EXPLAIN…</div>;
  }
  if (error) {
    return (
      <div className="h-full flex flex-col p-4 gap-2">
        <div className="nv-insight nv-insight-danger">
          <AlertTriangle size={14} className="shrink-0 mt-0.5" />
          <div>
            <div className="font-semibold">EXPLAIN failed</div>
            <div className="text-nv-textSubtle mt-0.5 whitespace-pre-wrap">{error}</div>
          </div>
        </div>
      </div>
    );
  }
  if (!normalized) {
    return <p className="text-xs text-nv-textMuted p-4">Sin plan para mostrar.</p>;
  }

  return (
    <div className={`flex flex-col overflow-hidden rounded border border-nv-border bg-nv-panel/30 ${compact ? '' : 'h-full min-h-0'}`}>
      <div className="flex items-center border-b border-nv-border bg-nv-toolbar text-xs shrink-0">
        {[
          ['visual', 'Visual'],
          ['grid', 'Grid'],
          ['info', 'Insights'],
          ['json', 'JSON'],
        ].map(([id, label]) => (
          <button
            key={id}
            type="button"
            onClick={() => setTab(id)}
            className={`px-3 py-1 border-r border-nv-border ${tab === id ? 'bg-nv-panel text-nv-text border-b-2 border-b-nv-accent -mb-px font-medium' : 'text-nv-textSubtle hover:bg-nv-hover'}`}
          >
            {label}
          </button>
        ))}
        <span className="ml-auto pr-3 text-2xs text-nv-textSubtle flex items-center gap-2">
          {parsed.rows.length} node{parsed.rows.length === 1 ? '' : 's'}
          {maxCost > 0 && <> · Max cost: {maxCost.toFixed(3)}</>}
          {connectionId && (
            <AiAnalysisButton
              connectionId={connectionId}
              kind="explain"
              params={{ sql: sql || '', plan, engine }}
              identifier="explain"
              database={database}
              engine={engine}
              title="Análisis con IA — Plan"
              titleAttr="Analizar este plan de ejecución con IA"
            />
          )}
        </span>
      </div>

      <div className={`flex-1 overflow-hidden bg-nv-panel relative ${minH} ${compact ? 'max-h-72' : ''}`}>
        {tab === 'visual' && (
          parsed.nodes.length > 0 ? (
            <div className="absolute inset-0">
              <ReactFlow
                nodes={parsed.nodes}
                edges={parsed.edges}
                nodeTypes={nodeTypes}
                fitView
                minZoom={0.1}
                maxZoom={1.5}
                nodesDraggable={false}
                nodesConnectable={false}
                elementsSelectable={false}
                defaultEdgeOptions={{
                  type: 'smoothstep',
                  animated: false,
                  markerEnd: { type: 'arrowclosed', color: '#64748b', width: 16, height: 16 },
                  style: { stroke: '#64748b', strokeWidth: 2 },
                }}
                proOptions={{ hideAttribution: true }}
                style={{ width: '100%', height: '100%' }}
              >
                <FitViewOnLoad count={parsed.nodes.length} />
                <Background gap={16} size={1} />
                <Controls showInteractive={false} />
                <MiniMap
                  zoomable
                  pannable
                  nodeColor={() => '#64748b'}
                  maskColor="rgba(15,23,42,0.35)"
                  style={{ width: 72, height: 48, background: 'var(--nv-panel, #1e293b)' }}
                  className="!border !border-nv-border !rounded-sm !shadow-md"
                />
              </ReactFlow>
            </div>
          ) : (
            <div className="h-full overflow-auto p-3 space-y-2">
              <p className="text-xs text-nv-textMuted">No se pudo construir el árbol visual. JSON crudo:</p>
              <pre className="text-xs font-mono whitespace-pre-wrap">{JSON.stringify(normalized, null, 2)}</pre>
            </div>
          )
        )}

        {tab === 'grid' && (
          parsed.rows.length > 0 ? (
            <div className="h-full overflow-auto">
              <table className="w-full text-xs border-collapse">
                <thead className="sticky top-0 bg-nv-gridHeader">
                  <tr>
                    {['Operation', 'Table', 'Cost', 'Rows', 'Time', 'Index/Extra', 'Filter', 'Risk'].map((h) => (
                      <th key={h} className="text-left px-2 py-1 border-b border-nv-border font-semibold">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {parsed.rows.map((row) => (
                    <tr key={row.id} className="border-b border-nv-borderLight hover:bg-nv-hover">
                      <td className="px-2 py-0.5 font-mono" style={{ paddingLeft: 8 + row.depth * 14 }}>{row.operation}</td>
                      <td className="px-2 py-0.5">{row.table ?? ''}</td>
                      <td className="px-2 py-0.5">{row.cost ?? ''}</td>
                      <td className="px-2 py-0.5">{row.rows ?? ''}</td>
                      <td className="px-2 py-0.5">{row.time ?? ''}</td>
                      <td className="px-2 py-0.5 max-w-xs truncate" title={row.extra}>{row.extra ?? ''}</td>
                      <td className="px-2 py-0.5 max-w-xs truncate" title={row.filter}>{row.filter ?? ''}</td>
                      <td className="px-2 py-0.5">
                        <span className={`nv-risk-badge nv-risk-${row.risk ?? 'low'}`}>{row.risk ?? 'low'}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="p-3 text-xs text-nv-textMuted">No plan rows parsed.</div>
          )
        )}

        {tab === 'info' && (
          <div className="h-full overflow-auto p-3 text-xs space-y-3">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
              <StatCard label="Engine" value={engine ?? 'unknown'} />
              <StatCard label="Nodes" value={String(parsed.rows.length)} />
              <StatCard label="Max cost" value={maxCost ? maxCost.toFixed(3) : '—'} />
              <StatCard label="Tables" value={String(parsed.rows.filter((r) => r.table).length)} />
            </div>
            <div className="space-y-2">
              <div className="font-semibold flex items-center gap-1"><Lightbulb size={13} /> Recommendations</div>
              {insights.map((ins, i) => <InsightCard key={i} insight={ins} />)}
            </div>
            {parsed.rows[0] && (
              <div className="border border-nv-border rounded p-2 bg-nv-toolbar">
                <b>Root:</b> {parsed.rows[0].operation}
                {parsed.rows[0].table && <> · <b>Table:</b> {parsed.rows[0].table}</>}
              </div>
            )}
          </div>
        )}

        {tab === 'json' && (
          <pre className="h-full overflow-auto p-3 text-xs font-mono whitespace-pre-wrap">{JSON.stringify(normalized, null, 2)}</pre>
        )}
      </div>
    </div>
  );
}
